provider "aws" {
  region = "us-east-1" # specify your region
}

resource "aws_route53_zone" "primary" {
  name = "example.com"
}

resource "aws_cloudwatch_log_group" "route53_example_com" {
  name = "/aws/route53/example.com"
}

resource "aws_cloudwatch_log_stream" "route53_query_logging" {
  name           = aws_route53_zone.primary.name
  log_group_name = aws_cloudwatch_log_group.route53_example_com.name
}

resource "aws_cloudwatch_log_resource_policy" "route53_query_logging_policy" {
  policy_name = "route53-query-logging-policy"

  policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid       = "CloudWatchLogsQueryLogging"
        Effect    = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action   = "logs:CreateLogStream"
        Resource = "${aws_cloudwatch_log_group.route53_example_com.arn}:*"
        Condition = {
          StringEquals = {
            "aws:SourceOwner": data.aws_caller_identity.current.account_id
            "aws:SourceArn": data.aws_route53_zone.primary.arn
          }
        }
      },
      {
        Sid       = "CloudWatchLogsQueryLoggingWrite"
        Effect    = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action   = "logs:PutLogEvents"
        Resource = "${aws_cloudwatch_log_group.route53_example_com.arn}:log-stream:${aws_cloudwatch_log_stream.route53_query_logging.name}"
        Condition = {
          StringEquals = {
            "aws:SourceOwner": data.aws_caller_identity.current.account_id
            "aws:SourceArn": data.aws_route53_zone.primary.arn
          }
        }
      }
    ]
  })
}

resource "aws_route53_query_log_config" "primary_logging" {
  zone_id = aws_route53_zone.primary.id
  cloudwatch_logs_log_group_arn = aws_cloudwatch_log_group.route53_example_com.arn
  cloudwatch_logs_role_arn      = aws_iam_role.route53_cloudwatch_access.arn
}

resource "aws_iam_role" "route53_cloudwatch_access" {
  name = "route53_cloudwatch_access_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid = ""
        Effect = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "route53_cloudwatch_write" {
  role       = aws_iam_role.route53_cloudwatch_access.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRoute53QueryLogPublishingPolicy"
}

