provider "aws" {
  region = "us-east-1"
}

resource "aws_route53_zone" "primary" {
  name = "example.com"
}

resource "aws_route53_record" "blue_env" {
  zone_id    = aws_route53_zone.primary.zone_id
  host_weight = "90"
  name        = "myapp.example.com"
  type        = "CNAME"
  ttl         = "60"
  records = ["blue.example.com"]
}

resource "aws_route53_record" "green_env" {
  zone_id    = aws_route53_zone.primary.zone_id
  host_weight = "10"
  name        = "myapp.example.com"
  type        = "CNAME"
  ttl         = "60"
  records = ["green.example.com"]
}
```

This configuration sets up a weighted DNS routing policy between two ECS Elastic Beanstalk environments named "blue" and "green" using AWS Route 53. each entry directs traffic with weights 90% and 10% respectively, facilitating blue-green deployment.

