provider "aws" {
  region = "us-west-2" # You can change the region as needed
}

resource "aws_s3_bucket" "elastic_beanstalk" {
  bucket = "elastic-beanstalk-${random_id.this.hex}"
  acl    = "private"
}

resource "random_id" "this" {
  byte_length = 8
}

resource "aws_iam_role" "eb_environment_service" {
  name = "eb_environment_service_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "elasticbeanstalk.amazonaws.com"
        },
      },
    ],
  })
}

resource "aws_iam_instance_profile" "eb_instance_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_environment_service.name
}

resource "aws_s3_bucket_lifecycle_configuration" "elastic_beanstalk" {
  bucket = aws_s3_bucket.elastic_beanstalk.id

  rule {
    id = "log"

    filter {
      prefix = "elasticbeanstalk"
    }

    transition {
      days          = 30
      storage_class = "ONEZONE_IA"
    }

    expiration {
      days = 90
    }
  }
}

resource "aws_elastic_beanstalk_application" "my_app" {
  name = "my-app"
}

resource "aws_elastic_beanstalk_configuration_template" "my_app_template" {
  name         = "my-app-template"
  application  = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.2 running Python 3.8"

  setting {
    namespace = "aws:ec2:vpc"
    name      = "VPCId"
    value     = "vpc-12345678" # Replace with your VPC ID
  }

  setting {
    namespace = "aws:ec2:vpc"

    name      = "Subnets"
    value     = "subnet-12345678,subnet-23456789" # Replace with your subnet IDs
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"

    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_instance_profile.name
  }
}

resource "aws_elastic_beanstalk_environment" "my_env" {
  name                = "my-env"
  application         = aws_elastic_beanstalk_application.my_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.4.2 running Python 3.8"
  cname_prefix        = "my-env"

  tier {
    name     = "WebServer"
    type     = "Standard"
    version  = "1"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"

    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }
}

resource "aws_db_instance" "default" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0.23"
  instance_class       = "db.t2.micro"
  name                 = "mydb"
  username             = "admin"
  password             = "supersecret" # Consider using more secure methods to handle passwords
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true

  vpc_security_group_ids = ["sg-12345678"] # Replace with your security group ID
  subnet_group_name      = aws_db_subnet_group.default.name
  publicly_accessible    = true
}

resource "aws_db_subnet_group" "default" {
  name       = "default"
  subnet_ids = ["subnet-12345678", "subnet-23456789"] # Replace with your subnet IDs
  tags = {
    Name = "default"
  }
}
