  map_public_ip_on_launch = true
  availability_zone = "${var.aws_region}"

  tags = {
    Name = "eb_subnet_public_1"
  }
}

resource "aws_subnet" "eb_subnet_public_2" {
  vpc_id            = aws_vpc.eb_vpc.id
  cidr_block         = "10.0.2.0/24"
  map_public_ip_on_launch = true
  availability_zone = "${var.aws_region}"

  tags = {
    Name = "eb_subnet_public_2"
  }
}

resource "aws_route_table" "eb_route_table" {
  vpc_id = aws_vpc.eb_vpc.id
}

resource "aws_route" "eb_route" {
  route_table_id = aws_route_table.eb_route_table.id
  destination_cidr_block = "0.0.0.0/0"
  gateway_id = aws_internet_gateway.eb_gateway.id
}

resource "aws_route_table_association" "route_table_assoc_1" {
  subnet_id          = aws_subnet.eb_subnet_public_1.id
  route_table_id = aws_route_table.eb_route_table.id
}

resource "aws_route_table_association" "route_table_assoc_2" {
  subnet_id          = aws_subnet.eb_subnet_public_2.id
  route_table_id = aws_route_table.eb_route_table.id
}

resource "aws_security_group" "eb_env_sg" {
  name        = "eb_env_sg"
  description = "Security group for Elastic Beanstalk environments"
  vpc_id     = aws_vpc.eb_vpc.id
  ingress {
    from_port   = 80
    to_port     = 80
    protocol   = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  egress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
  tags = {
    Name = "eb_env_sg"
  }
}

resource "aws_db_subnet_group" "shared_rds" {
  name       = "shared_rds"
  subnet_ids  = [aws_subnet.eb_subnet_public_1.id, aws_subnet.eb_subnet_public_2.id]

  tags = {
    Name = "shared_rds"
  }
}

resource "aws_elastic_beanstalk_environment" "eb_env_1" {
  application_name = "my-application"
  cname        = "environment1.elasticbeanstalk.com"
  environment_name = "eb_env_1"

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "ServiceRole"
    value     = "awseb-service-role"
  }

  setting {
    namespace = ""
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:ec2:instances"
    name      = "InstanceType"
    value     = "t2.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name = "VPCId"
    value = aws_vpc.eb_vpc.id
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "AssociatedPublicIpAddress"
    value     = "true"
  }

  resource_lifecycle {
    lookup    = "eb_env_1"
  }
}

resource "aws_elastic_beanstalk_environment" "eb_env_2" {
  application_name = "my-application"
  cname          = "environment2.elasticbeanstalk.com"
  environment_name = "eb_env_2"

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "DBInstanceClass"
    value     = "t2.micro"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "VPCID"
    value     = aws_vpc.eb_vpc.id
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "Public-associated Subnets"
    value     = "${concat(aws_subnet.eb_subnet_public_1, ",", aws_subnet.eb_subnet_public_2)}"
  }

  resource_lifecycle {
    lookup = "eb_env_2"
  }
}
```

