    type = "ReturnIntent"
  }
  abort_statement {
    message = "Sorry, I could not understand. Please try again."
  }
  role_arn = aws_iam_role.lex_role.arn

  # Define the PizzaOrderIntent with a follow-up prompt
  intent {
    name                       = "PizzaOrderIntent"
    sample_utterances {
      content = "I want to order a pizza"
    }
    slot {
      name           = "PizzaType"
      slot_type      = "PizzaTypeList" # Assume this is a custom list type
      elicit_spot {
        max_attempts = 3
        message      = "What type of pizza would you like to order?"
      }
      follow_up_prompt {
