          max_attempts    = 3
          retries_desc    = "Did you say that?"
          voice_id        = "Salli"
        }
      }
    }
    slot {
      name           = "Size"
      slot_type      = "AMAZON.NUMBER"
    }
    fulfillment_activity {
      type            = "ReturnIntent"
    }
  }
}

