  slot_type_values {
    value          = "Los Angeles"
  }
}

resource "aws_lex_slot" "departure_date" {
  name            = "DepartureDate"
  description     = "Date of departure"
  slot_type       = "AMAZON.DATE"
}

# Populate all slots in the intent
resource "aws_lex_intent_slot_eligibility" "eligibility_book_trip" {
  intent_name     = aws_lex_intent.book_trip_intent.name
  slot_name       = aws_lex_slot.destination.name
  slot_type       = aws_lex_slot.destination.slot_type

  slot_eligibility {
    slot_type       = aws_lex_slot.departure_city.slot_type
  }

  slot_eligibility {
    slot_type       = aws_lex_slot.departure_date.slot_type
  }
}
```

Note: You need to replace `"arn:aws:iam::123456789012:role/service-role/AmazonLexRole"` with your actual AWS IAM role ARN and `path/to/your/bot-definition.json` with the path to your bot definition JSON file.

