provider "aws" {
  region = "us-east-1" # Adjust the region as needed
}

resource "aws_lex_bot" "pizza_order_bot" {
  name       = "KidsPizzaOrderBot"
  role_arn   = aws_iam_role.lex_role.arn

  description = "This bot is designed to assist children in placing pizza orders."
  idle_session_ttl_in_seconds = 300
}

resource "aws_lex_intent" "children_order_intent" {
  name            = "ChildrenOrderIntent"
  confirmation_request_category = "Order"
  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      app_id           = "KidsPizzaOrderBot"
      version = "1.0"
    }
  }
}

resource "aws_lex_slot_type" "order_slot" {
  slot_type          = "List"
  alias              = "OrderSelection"
  description        = "Effective slot type for communicating order options."
}

resource "aws_lex_slot_type" "confirmation_slot" {
  slot_type         = "Confirmation"
  alias              = "ConfirmOrderIntent"
  few_only = true
}

resource "aws_lex_slot_type" "children_of" {
  slot_type         = "String"
  alias              = "ChildrenOrder"
  example_utterances {
    attributes = ["I am ▲ years old."]
  }
}

resource "aws_lex_slot_type" "order_details_slot" {
  slot_type        = "Custom"
  name = "OrderDetails"
  description = "Slot type to capture order details effectively."
  bundle = "OrderDetailsBundle"
}

resource "aws_lex_slot_type" "confirmation_details_slot" {
  slot_type       = "String"
  alias           = "ConfirmOrderDetails"
  example_utterances {
    attributes = ["Yes, I want the pizza"]
  }
}

resource "aws_lex_slot_type" "pizza_size_slot" {
  slot_type        = "List"
  alias            = "PizzaSize"
  example_utterances {
    sample_utterance = ["medium size", "large size"]
  }
  validation {
    parameter {
      name        = "size"
      parameter_constraints {
      valueA      = "medium"
      valueB      = "large"
      valueC      = "small"
      }}
  }
}

resource "aws_lex_slot_type" "response_slot" {
  slot_type       = "String"
  alias           = "OrderResponse"
  example_utterances {
    sample_utterance = ["yes", "no", "maybe"]
  }
  documentation = {
    sample_utterance = ["Yeah, I'm going with this order"]
  }
}

resource "aws_lex_dialog" "order_dialog" {
  name     = "ChildrenPizzaOrderDialog"
  builtInIntents = ["ChildOrderIntent", "ConfirmOrderIntent"]
  fulfillmentActivity = {
    type    = "CodeHook"
    codeHook {
      appID   = "${aws_lex_bot.pizza_order_bot.name}"
      version = "1.0"
    }
  }
}
resource "aws_lex_bot_version" "kids_bot_version" {
  bot_id       = "${aws_lex_bot.kids_order_bot.id}"
  checksum    = "CHECKSUM_PLACEHOLDER" # Use the actual checksum value of your bot's Amazon Lex runtime
  created     = true
}

resource "aws_lex_bot_alias" "alias_for_kids_order_bot" {
  bot_alias {
    bot_aliases = "KidsPizzaOrderBot"
    bot_versions = "${aws_lex_bot_version.kids_bot_version.id}"
  }
}

resource "aws_lex_bot_alias" "pizza_order_bot_alias" {
  bot_aliases = "PizzaOrderBot"
  bot_versions = "${aws_lex_bot_version.example_bot_version.id}"
}

resource "aws_lex_intent" "order_intent_with_slots" {
  intent_name = "ChildrenOrderIntent"
  slots {
  children_of   = "${aws_lex_slot_type.children_of.id}"
  order_details = "${aws_lex_slot_type.order_details.id}"
  confirmation_details = "${aws_lex_slot_type.confirmation_details.id}"
  }
}

resource "aws_lex_intent" "confirm_order_intent" {
  intent_name = "ConfirmOrderIntent"
  slots {
  confirmation_details  = "${aws_lex_slot_type.confirmation_details.id}"
  }
  sample_utterances {
    attributes = ["I want a medium sized pizza"]
    }
}

resource "aws_lex_keyboard_intent" "ChildrenOrderIntent" {
  intent_name   = "ChildrenOrderIntent"
  alias         = "ChildOrderNav"
  sampleUtterances {
    attributes = ["medium sized pizza", "large pizza", "small pizza", "yes I want the pizza", "no I don't want it"]
  }
  slotTypes {
    children_of   = "${aws_lex_slot_type.children_of.id}"
    order_details = "${aws_lex_slot_type.order_details.id}"
  }
}

output "kids_order_bot_arn" {
  value = "${aws_lex_bot.alias_for_kids_order_bot.bot_alias_arn}"
}

output "order_details_slot_type" {
  value = "${aws_lex_slot_type.order_details_slot_type.id}"
}

output "order_confirmation_slot_type" {
  value = "${aws_lex_slot_type.confirmation_details_slot_type.id}"
}

