provider "aws" {
  region = "us-east-1" # Specify your preferred AWS region
}

resource "aws_lex_bot" "pizza_order_bot" {
  name     = "PizzaOrderBot"
  role_arn = aws_iam_role.lex_role.arn
  description = "A bot to handle pizza orders"
}

resource "aws_iam_role" "lex_role" {
  name = "LexPizzaOrderBotRole"

  assume_role_policy  {
    statement = {
      actions = ["sts:AssumeRole"]
      effect  = "Allow"
      principals = {
        type        = "Service"
        identifiers = ["lex.amazonaws.com"]
      }
    }
  }
}

resource "aws_lambda_function" "order_handler_function" {
  function_name = "PizzaOrderHandler"
  role          = aws_iam_role.lex_role.ami_role_arn
  handler       = "orderBot.handler"
  runtime       = "python3.8"

  source_code = file("orderBot.py")
  description = "Handles pizza orders for Lex bot"

  timeout   = 5
  memory_size = 128
}

resource "aws_lex_intent" "handle_pizza_order_intent" {
  bot_name      = aws_lex_bot.pizza_order_bot.name
  bot_version  = aws_lex_bot.pizza_order_bot.latest_version
  intent_name   = "PizzaOrderIntent"
  slots = [
    {
      name              = "size"
      description       = "Choose the size of the pizza"
      type             = "AMAZON.DURATION"
      is_required      = true
      prompts = [
        "What size pizza would you like?",
        "Choose a size: small, medium, or large."
      ]
    }
  ]
  confirmation_prompt = {
    "prompt" = "Would you like to order a {Slot.Value} size pizza?"
    "rejection_statement" = "I can help you order a {Slot.Value} size pizza."
  }
  rejection_statement = "I am unable to comprehend your request"
  response_card_title = "Confirming your {Slot.size}"

  sample_utterances = [
    "I want a {size} pizza, {size} pizza",
    "Order a {size} pizza now",
    "Give me a {size} sized pizza",
    "{size} pizza please"
  ]

  fulfillment_activity = {
    type  = "CodeHook"
    parameters = {
      codeHook = {
        uri       = aws_lambda_function.order_handler_function.invoke_arn
        httpMethod = "POST"
      }
    }
  }
}

resource "aws_lex_slot_type" "size_slot_type" {
  slot_type_name            = "size"
  bot_id                   = aws_lex_bot.pizza_order_bot.bot_id
  bot_version              = aws_lex_bot.pizza_order_bot.latest_version
  value_selection_strategy = "FirstValid"
}

resource "aws_lex_slot_type" "pizza_slot_type" {
  slot_type_name  = "pizza"
  value_list = [
    "Margherita",
    "Pepperoni",
    "Hawaiian",
    "Garlic Butter",
    "Veggie"
  ]
}

