provider "aws" {
  region = "us-west-2" # specify your region
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name        = "my-firehose-delivery-stream"

  source_configuration {
    stream_name = aws_kinesis_stream.source_stream.name
    role_arn    = aws_iam_role.firehose_delivery_role.arn
  }

  destination {
    extended_s3_configuration {
      role_arn   = aws_iam_role.s3_writer_role.arn
      bucket_arn = aws_s3_bucket.target_bucket.arn
      buffer_size {
        interval_in_seconds = 300
        size_in_mbs         = 5
      }
      prefix              = "data/"
      error_output_prefix = "errors/"
      data_format_conversion_configuration {
        input_format_configuration {
          deserializer {
            open_x_json_ser_de {}
          }
        }
        output_format_configuration {
          serializer {
            parquet_ser_de {}
          }
        }
        schema_configuration {
          catalog_id = aws_glue_catalog_database.database.catalog_id
          database_name = aws_glue_catalog_database.database.name
          table_name    = aws_glue_catalog_table.table.name
          role_arn      = aws_iam_role.glue_role.arn
        }
      }
      dynamic_partitioning_configuration {
        enabled = true
        runtime_partition_configuration {
          partition_arn_regex           = ".*"
          case_sensitive                = false
          dynamic_partition_bind_json   = jsonencode({
            "year"    = "$${year}",
            "month"   = "$${month}",
            "day"     = "$${day}"
          })
        }
      }
    }
  }
}

resource "aws_kinesis_stream" "source_stream" {
  name     = "source-stream"
  shard_count = 1
}

resource "aws_s3_bucket" "target_bucket" {
  bucket = "my-target-bucket"
  acl    = "private"
}

resource "aws_iam_role" "firehose_delivery_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      },
    ]
  })

  inline_policy {
    name   = "FirehosePolicy"
    policy = data.aws_iam_policy_document.firehose.json
  }
}

data "aws_iam_policy_document" "firehose" {
  statement {
    actions   = ["kinesis:DescribeStream*", "kinesis:Get*"]
    resources = [aws_kinesis_stream.source_stream.arn]
  }
}

resource "aws_iam_role" "s3_writer_role" {
  name = "s3_writer_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
        Effect = "Allow"
      },
    ]
  })

  inline_policy {
    name   = "s3_access_policy"
    policy = data.aws_iam_policy_document.s3_access.json
  }
}

data "aws_iam_policy_document" "s3_access" {
  statement {
    actions   = ["s3:AbortMultipartUpload", "s3:GetBucketLocation", "s3:GetObject", "s3:ListBucket", "s3:ListBucketMultipartUploads", "s3:PutObject"]
    resources = [
      aws_s3_bucket.target_bucket.arn,
      "${aws_s3_bucket.target_bucket.arn}/*"
    ]
  }
}

resource "aws_glue_catalog_database" "database" {
  name = "my_database"
}

resource "aws_glue_catalog_table" "table" {
  name       = "my_table"
  database_name = aws_glue_catalog_database.database.name

  table_type     = "EXTERNAL_TABLE"
  storage_descriptor {
    columns {
      name = "column1"
      type = "string"
    }
    location       = "s3://${aws_s3_bucket.target_bucket.bucket}/data/"
  }
}

resource "aws_iam_role" "glue_role" {
  name = "glue_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "glue.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      },
    ]
  })

  inline_policy {
    name   = "GluePolicy"
    policy = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Action = [
            "s3:GetObject",
            "s3:PutObject",
            "kms:Decrypt"
          ]
          Effect = "Allow"
          Resource = aws_s3_bucket.target_bucket.arn
        },
        {
          Action = [
            "kms:DescribeKey"
          ]
          Effect = "Allow"
          Resource = "*"
        }
      ]
    })
  }
}

