  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "glue.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      },
    ]
  })

  inline_policy {
    name   = "GluePolicy"
    policy = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Action = [
            "s3:GetObject",
            "s3:PutObject",
            "kms:Decrypt"
          ]
          Effect = "Allow"
          Resource = aws_s3_bucket.target_bucket.arn
        },
        {
          Action = [
            "kms:DescribeKey"
          ]
          Effect = "Allow"
          Resource = "*"
        }
      ]
    })
  }
}
