provider "aws" {
  region = "us-east-1" # Modify the region according to your setup
}

resource "aws_kinesis_firehose_delivery_stream" "my_delivery_stream" {
  name           = "my-opensearch-delivery-stream"
  role_arn       = aws_iam_role.firehose.arn
  kinesis_stream_arn = aws_kinesis_stream.my_stream.arn
  compression_format = "UNCOMPRESSED"
  s3_destination_configuration {
    bucket_arn = aws_s3_bucket.my_bucket.arn
    role_arn   = aws_iam_role.s3.arn
    buffer_size = 10
  }
  cloudwatch_logging_options {
    enabled = true
  }
  delivery_stream_format_configuration {
    delivery_stream_format = "OPENSEARCH_JSON"
  }
  opensearch_destination_configuration {
    role_arn             = aws_iam_role.opensearch.arn
    buffering_hints {
      interval_length = "60" # Buffering interval length in seconds.
      size            = "4" # Buffering size in MiB
    }
    restart_checkpoint {
      hourly_flush_faill_time  = "PT1H"
      checkpoint_interval  = "PT5M"
      probation_period      = "PT60S"
    }
    opensearch_configurations {
      cluster_arn  = var.opensearch_cluster_arn
      index_name   = var.opensearch_index_name
      boto3_role_arn = var.opensearch_boto3_role_arn
      directly_connect_to_es = true
      sub_steps {
        options {
          put_request_body     = true
          raw_data             = true
        }
        processing_configuration {
          enabled         = true
          options {
            extract_doc_type    = false
            extract_doc_id      = false
          }
          processor_configurations {
            options {
              type     = "DOCUMENT_TYPE_AWS_HO_CONS"
              schema    = var.opensearch_document_type_schema # Replace with your document type schema
            }
          }
        }
      }
    }
  }
}

resource "aws_iam_role" "firehose" {
  name = "firehose_role"
  assume_role_policy = data.aws_iam_policy_document.firehose.json
}

resource "aws_kinesis_stream" "my_stream" {
  name             = "my-kinesis-stream"
  shard_level_metrics {
    enabled          = [ "IncomingBytes", "OutgoingBytes" ]
    shard_level_metrics_configuration {
      shard_level_metrics_enabled = true
    }
  }
  retention_period_hours = 24
}

resource "aws_iam_role" "s3" {
  name = "s3_kinesis_role"
  assume_role_policy = "s3_kinesis_policy"
}

data "aws_iam_policy_document" "firehose" {
  statement {
    actions = [
      "kinesis:PutRecord",
      "kinesis:PutRecordBatch",
    ]
    resources = [
      "*", 
    ]
    effect = "Allow"
  }

  statement {
    actions = [
      "s3:GetObject",
      "s3:PutObject",
      "s3:Abort*",
      "s3:ListBucket",
    ]
    resources = [
      "${aws_s3_bucket.my_bucket. **"}",
    ]
    effect = "Allow"
  }

  statement {
    actions = [
      "iam:PassRole"
    ]
    resources = [
      "${aws_iam_role.s3.arn}",
    ]
    effect = "Allow"
  }
}

data "aws_iam_policy_document" "s3" {
  statement {
    actions = [
      "s3:ListBucket",
    ]
    resources = [
      "${aws_s3_bucket.my_bucket. arn}"
    ]
    effect = "Allow"
  }

  statement {
    actions = [
      "s3:ListBucket",
      "s3:PutObject",
      "s3:GetObject",
    ]
    resources = [
      "arn:aws:s3:::*",
    ]
    effect = "Allow"
  }

  statement {
    actions = [
