resource "aws_kinesis_data_analytics_v2_application" "example" {
  name = "example-analytics-application"
  application_type = "SQL"

  # Assuming that a Kinesis Data Stream is already created
  inputs = [
    {
      name_prefix = "example-input"
      kinesis_input = {
        resource_arn = aws_kinesis_stream.example.arn
        role_arn = aws_iam_role.example_kinesis.arn
      }
    }
  ]

  output = [
    {
      name_prefix = "example-output"
      kinesis_output = {
        resource_arn = aws_kinesis_stream.example_output.arn
        role_arn = aws_iam_role.example_kinesis.arn
      }
    }
  ]

  environment_properties {
    property_groups = [
      {
        properties = [
          {
            name  = "CODE_VENDOR"
            value = "AWS/KDA"
          },
          {
            name  = "SQL_APPLICATION_ID"
            value = "${self.application_id}/SQL-1.0"
          },
          {
            name  = "SOURCE_SQL_VALIDATION_MODE"
            value = "NONE"
          }
        ]
      }
    ]
  }

  cloud_watch_logging_option = [
    {
      cloud_watch_logging_option_details = {
        log_stream_arn = aws_cloudwatch_log_stream.example.arn
        role_arn = aws_iam_role.example_iam_arn_for_logging.arn
      }
      log_types = ["APPLICATION", "STREAMING"]
    }
  ]
}

