    Environment = "primary"
    Region      = "eu-central-1"
  }
}

resource "aws_route53_traffic_policy" "low_load_policy" {
  name = "LowLoadPolicy"
  document = jsonencode({
    StartRule = "LowestLatencyRule",
    Rules = {
      LowestLatencyRule = {
        RuleType = "Latency",
        LatencyResourceRecords = [
          {
            Region = "us-east-1",
            ResourceRecord = {
              Value = "us-east-1-endpoint.example.com"
              Type  = "A"
            },
            HealthCheckId = aws_route53_health_check.us_east_1.id
          },
          {
            Region = "eu-central-1",
            ResourceRecord = {
              Value = "eu-central-1-endpoint.example.com"
              Type  = "A"
            },
            HealthCheckId = aws_route53_health_check.eu_central_1.id
          }
        ]
      }
    }
  })
}

resource "aws_route53_traffic_policy_instance" "low_load_instance" {
  name               = "LowLoadInstance"
  ttl                = 60
  traffic_policy_id  = aws_route53_traffic_policy.low_load_policy.id
  traffic_policy_version = aws_route53_traffic_policy.low_load_policy.latest_version
  hosted_zone_id     = aws_route53_hosted_zone.primary.zone_id

  rrset {
    name    = "primary"
    type    = "A"
    records = ["primary.example.com"]
  }
}
```
Replace placeholder values such as `example.com` and the endpoint values as necessary for your specific configuration.

