variable "cluster_name" {
  description = "The name of the EKS cluster"
  type        = string
}

data "aws_iam_policy" "cluster_policy" {
  name = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
}

data "aws_iam_policy_document" "eks_access" {
  statement {
    actions   = ["sts:AssumeRole"]
    principals {
      type        = "Service"
      identifiers = ["eks.amazonaws.com"]
    }

    resources = ["*"]
  }
}

resource "aws_iam_role" "eks_cluster" {
  name = var.cluster_name

  assume_role_policy {
    statement = data.aws_iam_policy_document.eks_access.json
  }

  policies {
    arn = data.aws_iam_policy.cluster_policy.arn
  }
}

resource "aws_eks_cluster" "example" {
  name     = var.cluster_name
  role_arn = aws_iam_role.eks_cluster.arn

  vpc_config {
    subnet_ids = ["subnet-abc12345", "subnet-abc12346"]

    endpoint_private_access = true
    endpoint_public_access = false
  }

  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_AmazonEKSClusterPolicy,
  ]

  provisioner "local-exec" {
    when    = "destroy"
    command = "aws eks --region us-east-1 update-kubeconfig --name ${self.name} --role-arn ${self.role_arn} --disable-aws-iam-auth --kubeconfig kubectl-configuration.yaml"
  }

  provisioner "local-exec" {
    when    = "create"
    command = "aws eks --region us-east-1 update-kubeconfig --name ${self.name} --role-arn ${self.role_arn} --kubeconfig kubectl-configuration.yaml"
  }
}

resource "aws_iam_role_policy_attachment" "eks_cluster_AmazonEKSClusterPolicy" {
  policy_arn = data.aws_iam_policy.cluster_policy.arn
  role       = aws_iam_role.eks_cluster.name
}

resource "aws_iam_role_policy_attachment" "eks_cluster_AmazonEKSServicePolicy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.eks_cluster.name
