  thumbprint_list = [data.tls_certificate.example.certificates.0.sha1_fingerprint]
  url             = aws_eks_cluster.example.identity[0].oidc.0.issuer

  tags = {
    Name = "example-OIDC"
  }
}

data "tls_certificate" "example" {
  url = aws_eks_cluster.example.identity[0].oidc.0.issuer
}

output "oidc_provider_arn" {
  value = aws_iam_openid_connect_provider.example.arn
}

output "oidc_issuer_url" {
  value = aws_eks_cluster.example.identity[0].oidc.0.issuer
}
```

**Notes:**
- Replace `"arn:aws:iam::YOUR_AWS_ACCOUNT_ID:role/EKS-role"` with the actual ARN for your IAM role that will be associated with the EKS cluster.
- Replace the subnet IDs with the appropriate subnet IDs from your VPC.
- Make sure you have the necessary IAM permissions for creating EKS clusters and OIDC providers.

