  name = "demo_eks"

  assume_role_policy {
    version = "2012-10-17"
    statement = {
      actions = ["sts:AssumeRole"]
      principals = [
        {
          type        = "Service"
          identifiers = ["eks.amazonaws.com"]
        },
      ]
      effect = "Allow"
    }
}

