provider "aws" {
  region = "us-west-2"
}

resource "aws_s3_bucket" "my_bucket" {
  bucket = "my-bucket"
  acl    = "private"

  lifecycle {
    prevent_destroy = false
    ignore_changes  = [
      versioning,
    ]
  }

  force_destroy = true

  metric_configuration {
    id = "my-bucket-metric"

    filter {
      and_operator {
        operators {
          subject {
            bucket_name = aws_s3_bucket.my_bucket.id
          },
          predicate {
            object_key = "*"
          },
          action {
            is                = "all"
          }
        }
      }
    }
    fulfillment {
      destination {
        s3 {
          bucket {
            account_id = data.aws_caller_identity.current.account_id
            bucket_arn = aws_s3_bucket.metric_target.arn
            key        = "my_bucket_metric.json"
          }
        }
      }
    }
  }
}

