  name           = "terraform-state-lock"
  hash_key       = "LockID"
  billing_mode   = "PAY_PER_REQUEST"

  attribute {
    name = "LockID"
    type = "S"
  }

  attribute {
    name = "BillingMode"
    type = "S"
    default_action = "PUT"
  }

  tags = {
    Name = "TerraformStateLocks"
  }
}

