provider "aws" {
  region = "us-east-1" # Ensure to use your desired region
}

resource "aws_s3_bucket" "terraform_state" {
  bucket = "my-terraform-state-bucket"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  public_access_block_configuration {
    block_public_acls       = true
    ignore_public_acls      = true
    block_public_policy     = true
    restrict_public_buckets = true
  }

  tags = {
    Name = "TerraformStateBucket"
  }
}

resource "aws_dynamodb_table" "terraform_locks" {
  name           = "terraform-state-lock"
  hash_key       = "LockID"
  billing_mode   = "PAY_PER_REQUEST"

  attribute {
    name = "LockID"
    type = "S"
  }

  attribute {
    name = "BillingMode"
    type = "S"
    default_action = "PUT"
  }

  tags = {
    Name = "TerraformStateLocks"
  }
}
```

Ensure to replace `"my-terraform-state-bucket"` with a unique S3 bucket name. Use the DynamoDB table name `"terraform-state-lock", the subclass name, and the hash key `"LockID"` appropriately if other naming conventions apply to your context. Adjust the regions and tags as needed for your specific implementation.

