    rule {
      enabled = true
      rule {
        object_lock_retention {
          mode  = "COMPLIANCE"
          days  = 5
        }
        ignore_io_status = false
    }
    mfa_requirement = {
      enable = true
      suntimes = {
        days = 0
      }
    }
  }
}
```

