provider "aws" {
  region = "us-east-1"
}

data "aws_availability_zones" "available" {}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_subnet" "public" {
  count                   = length(data.aws_availability_zones.available.names)
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[count.index]
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }
}

resource "aws_route_table_association" "public" {
  count          = length(aws_subnet.public)
  route_table_id = aws_route_table.public.id
  subnet_id      = aws_subnet.public[count.index].id
}

resource "aws_subnet" "private" {
  count             = length(data.aws_availability_zones.available.names) * 2
  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index + count.index/2)
  availability_zone = data.aws_availability_zones.available.names[count.index % length(data.aws_availability_zones.available.names)]
}

resource "aws_instance" "latest_ami" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["amzn2-ami-hvm-*-x86_64-gp2"]
  }
}

data "aws_ami" "amazon_linux" {
  filter {
    name   = "name"
    values = [aws_instance.latest_ami.ami_ids[0]]
  }
}

resource "aws_launch_template" "lt" {
  name = "ec2-fleet-template"

  image_id               = data.aws_ami.amazon_linux.id
  instance_type          = "t3.micro"
  vpc_security_group_ids = ["sg-xxxxxxxx"] // Substitute with your VPC Security Group ID

  network_interfaces {
    associate_public_ip_address = true
    subnet_id                   = element(aws_subnet.public.*.id, 0) // Launch into first public subnet
  }
}

resource "aws_ec2_fleet" "fleet" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.lt.id
      version            = "$Latest"
    }

    overrides {
      instance_type         = "t3.micro"
      max_price             = "0.068"
      subnet_id             = element(aws_subnet.public.*.id, 0)
      weight                = 1
      instance_count        = 5
    }

    overrides {
      instance_type         = "t3.micro"
      max_price             = "0.068"
      subnet_id             = element(aws_subnet.private.*.id, 0)
      weight                = 2
      instance_count        = 4
      allocation_strategy   = "lowestPrice"
      instance_lifetime_tenancy = "spot"
    }
  }

  target_capacity_spec {
    default_target_capacity_type = "on-demand"
    on_demand_target_capacity    = 5
    spot_target_capacity         = 4
  }
}

