```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_redshift_cluster" "redshift_cluster" {
  cluster_identifier = "my-redshift-cluster"
  node_type         = "dc2.large"
  master_username   = "admin"
  master_password   = var.redshift_master_password
  db_name          = "dev"
  cluster_type     = "multi-node"
  encrypted        = true
  publicly_accessible = false

  availability_zone = ["us-east-1a", "us-east-1b"]

  vpc_security_group_ids = [aws_security_group.redshift_security_group.id]

  number_vpc_nodes     = 2
}

resource "aws_security_group" "redshift_security_group" {
  name        = "redshift-security-group"
  description = "Security group for Redshift cluster"

  ingress {
    rule = "postgresql"
    from_port = 5439
    to_port   = 5439
    protocol = "tcp"
    self = true
  }

  ingress {
    rule = "tcp"
    from_port = 8080
    to_port   = 8080
    protocol = "tcp"
    security_groups = [aws_security_group.redshift_security_group.id]
  }

  egress {
    rule       = "-1"
    from_port  = 0
    to_port    = 0
    protocol    = "-1"
  }
}

resource "aws_redshift_subnet_group" "redshift_subnet_group" {
  name       = "my-redshift-subnet-group"
  description = "Redshift subnet group"
  subnet_ids = [aws_subnet.redshift_subnet_1.id, aws_subnet.redshift_subnet_2.id]

  subnets = [
    {
      subnet_id         = aws_subnet.redshift_subnet_1.id
      subnet_availability_zone = "us-east-1a"
      subnet_availability_zone_name = "us-east-1a"
    },
    {
      subnet_id         = aws_subnet.redshift_subnet_2.id
      subnet_availability_zone = "us-east-1b"
      subnet_availability_zone_name = "us-east-1b"
    }
  ]
}

module "redshift_subnets" {
  source = "terraform-aws-modules/vpc/aws"

  vpc_id      = aws_vpc.main.id
  create_vpc  = false

  redshift_subnets = [
    {
      cidr_block = "172.31.0.0/16"
      map_public_ip_on_launch = false
      availability_zone_id = "us-east-1a"
    },
    {
      cidr_block = "172.31.0.0/16"
      map_public_ip_on_launch = false
      availability_zone_id = "us-east-1b"
    }
  ]
}
```

This code sets up a multi-node Amazon Redshift cluster spanning two availability zones (`us-east-1a` and `us-east-1b`) in the given region, ensuring fault tolerance. The cluster is securely configured with a VPC security group, and subnets are explicitly assigned to support the deployment across multiple Availability Zones.

