  bucket = "sagemaker-model-artifacts-bucket" # Give a unique name
  acl    = "private"
}

# Define a SageMaker model
resource "aws_sagemaker_model" "example_model" {
  name               = "example-model"
  execution_role_arn = aws_iam_role.sagemaker_role.arn

