module "cache" {
  source  = "terraform-aws-modules/elasticache/aws"
  version = "latest"

  this_prefix                 = "example"
  this_cache_subnet_name      = "${this_prefix}_cache_subnet"
  this_cache_subnet_azs      = ["us-east-1a", "us-east-1b"]
  this_security_group_name   = "${this_prefix}_cache_sg"
  this_cache_cluster_id      = "${this_prefix}-mycache"
  this_cache_node_type       = "cache.t2.small"
  this_cache_num_cache_nodes = 1
  this_cache_engine_version  = "1.4"
  this_engine               = "memcached"
  this_port                 = "11211"
  this_cache_security_group_rules = [
    {
      cidr_blocks = ["0.0.0.0/0"]
      description = "Allow access from the internet"
      # In practice, adjust CIDR blocks to match your applications' source IP for security
      from_port   = "11211"
      to_port     = "11211"
      protocol   = "tcp"
    }
  ]
  this_cache_subnet = {
    "${this_cache_subnet_name}-us-east-1a" = {
      name        = "${this_prefix}cache-subnet-a"
      subnet      = "us-east-1a"
      tags = {
        Name = "Cache Subnet A"
      }
      availability_zone = "us-east-1a"
    }
    "${this_cache_subnet_name}-us-east-1b" = {
      name        = "${this_prefix}cache-subnet-b"
      subnet      = "us-east-1b"
      tags = {
        Name = "Cache Subnet B"
      }
      availability_zone = "us-east-1b"
    }
  }
}

