provider "google" {
  project = var.project_id
  region  = "us-east1"
}

variable "project_id" {
  description = "The ID of the Google Cloud project"
  type        = string
}

resource "google_container_cluster" "msk_cluster" {
  name     = "msk-cluster"
  location = "us-east1"

  initial_node_count = 3

  private_cluster_config {
    enable_private_nodes = true
  }

  master_auth {
    username = ""
    password = ""
  }

  network_policy {
    enabled = true
  }

  ip_allocation_policy {
    cidr_block = "10.1.0.0/16"
  }
}

resource "google_container_service" "msk_serv" {
  name             = "msk-service"
  location         = "us-east1"
  description      = "Managed service for MSK cluster"
  cluster          = google_container_cluster.msk_cluster.id
}

resource "google_kms_key_ring" "key_ring" {
  location = "global"
  version = 1
  purpose = "cryptoKeyArchive"
  rotation_period = "3650d"
}

resource "google_kms_crypto_key" "crypto_key" {
  key_ring = google_kms_key_ring.key_ring.id
  location = "global"
}

resource "google_storage_bucket_iam_policy" "s3_bucket" {
  bucket = "your-s3-bucket-name"
  role    = "roles/storage.objectViewer"
}

