  name     = "msk-logs-bucket"
  location = "US"
  project  = var.project_id
}

resource "google_logging_buckets" "logs_bucket" {
  name  = google_storage_bucket.msk_logs_bucket.name
  parent = var.project_id
}

resource "google_logging_sinks_v1_logging_service" "log_sink" {
  name            = "log-sink"
  destination     = google_storage_bucket.msk_logs_bucket.id
  filter          = "resource.type="k8s_cluster""
}

resource "google_container_node_pool" "msk_node_pool" {
  cluster       = google_container_cluster.msk_cluster.id
  location      = google_container_cluster.msk_cluster.location
  name          = "node-pool"
  node_count    = 3
  node_config {
    machine_type = "e2-standard-4"
  }
}

