provider "google" {
  project = var.project_id
  region  = "us-east1"
}

variable "project_id" {
  description = "The ID of the Google Cloud project"
  type        = string
}

resource "google_container_cluster" "msk_cluster" {
  name     = "msk-cluster"
  location = "us-east1"

  initial_node_count = 3

  private_cluster_config {
    enable_private_nodes = true
  }

  master_auth {
    username = ""
    password = ""
  }

  network_policy {
    enabled = true
  }

  ip_allocation_policy {
    cidr_block = "10.1.0.0/16"
  }
}

resource "google_container_service" "msk_serv" {
  name             = "msk-service"
  location         = "us-east1"
  description      = "Managed service for MSK cluster"
  cluster          = google_container_cluster.msk_cluster.id
}

resource "google_kms_key_ring" "key_ring" {
  location = "global"
  version = 1
  purpose = "cryptoKeyArchive"
  rotation_period = "3650d"
}

resource "google_kms_crypto_key" "crypto_key" {
  key_ring = google_kms_key_ring.key_ring.id
  location = "global"
}

resource "google_storage_bucket_iam_policy" "s3_bucket" {
  bucket = "your-s3-bucket-name"
  role    = "roles/storage.objectViewer"
}

resource "google_storage_bucket" "msk_logs_bucket" {
  name     = "msk-logs-bucket"
  location = "US"
  project  = var.project_id
}

resource "google_logging_buckets" "logs_bucket" {
  name  = google_storage_bucket.msk_logs_bucket.name
  parent = var.project_id
}

resource "google_logging_sinks_v1_logging_service" "log_sink" {
  name            = "log-sink"
  destination     = google_storage_bucket.msk_logs_bucket.id
  filter          = "resource.type="k8s_cluster""
}

resource "google_container_node_pool" "msk_node_pool" {
  cluster       = google_container_cluster.msk_cluster.id
  location      = google_container_cluster.msk_cluster.location
  name          = "node-pool"
  node_count    = 3
  node_config {
    machine_type = "e2-standard-4"
  }
}
```

**Note:** Replace placeholder values such as `your-s3-bucket-name` with actual values specific to your setup. Ensure that the bucket permissions and other configurations are secured according to your requirements.

