}

resource "aws_elasticsearch_domain" "msk_domain" {
  domain_name = "my-msk-domain"

  cluster_config {
    instance_type   = "kmsEncryptionEnabled"
    instance_count  = 3
  }

  ebs_options {
    ebs_enabled = true
    volume_type = "gp2"
    volume_size = 10
  }

  encrypt_at_rest {
    encryption_key_id = "alias/aws/secretsmanager/my-msk-encryption-key"
  }

  snapshot_options {
    automated_snapshot_start_hour = 0
  }

  access_policies = [
    {
      principal   = {
        type = "ELLASTICSEARCH_ROLE"
        identifiers = ["arn:aws:iam::123456789012:role/my-iam-role"]
      },
      action    = "ESHttpGet",
      resources = [
        {
          type = "Domain",
          identifiers = ["${aws_elasticsearch_domain.msk_domain.domain_arn}"]
        },
        {
          type   = "LogGroup",
          identifiers = ["${aws_elasticsearch_domain.msk_domain.domain_arn}"]
        },
        {
          type    = "Resource",
          identifiers = ["${aws_elasticsearch_domain.msk_domain.domain_arn}/_snapshot/_all/_search"]
        }
      ]
    }
  ]

  tags = {
    ElasticSearch  = "true"
    Domain        = "my-msk-domain"
  }
}

resource "aws_global_cluster" "my_mskec_global_cluster" {
  cluster_name    = "my	mskec_Cluster"
  cluster_endpoint_configuration {
    domain    = "my_mskec_domain"
    client_endpoint {
      cliendId = "client-msk"
      url      = "https://${aws_elasticsearch_domain.msk_domain.endpoint}"
      security_policy = "TLS_1_2"
    }
    clientSearchEndpoint {
      url = "https://${aws_elasticsearch_domain.msk_domain.endpoint}/_search"
      security_policy = "TLS_1_2"
      vpc_endpoints = ["${aws_elasticsearch_domain.msk_domain.endpoint}", "${aws_elasticsearch_domain.msk_domain.endpoint}/_snapshot/"]
    }
  }

  elasticsearch_cluster_endpoint_configuration {
    vpc_config = {
      security_group_ids = ["${aws_security_group.msk_cluster_sg.id}"]
      subnet_ids = ["${aws_security_group.msk_cluster_sg.id}"]
      security_group_configuration {
        endpoint_security_group_ids = ["${aws_security_group.msk_cluster_sg.id}"]
        endpoint_id = "client-msk"
        vpc_id  = "vpc-12345678"
      }
    }
  }
  cluster_endpoint {
    client_endpoint {
      endpoint_id = "client-msk"
      type  = "MEMBER"
      security_config {
        security_policy = "TLS_1_2"
        client_id cert = "${aws_elasticsearch_domain.msk_domain.endpoint_certificate_arn}"
        security_policy = "NONE"
        security_type   = "IPV4"
        node_to_node_encryption  = false
      }
    }
    node_endpoint {
      node_id = "node-1"
      type    = "DATA_NODE"
    }
    node_endpoint {
      node_id = "node-2"
      type    = "INGEST_NODE"
    }
    node_endpoint {
      node_id = "node-3"
      type    = "COORDINATOR"
    }
    node_endpoint = {
      node_id = "node-4"
      type    = "MANAGER"
    }
  }
  cross-cluster_triggers = [
    {
      triggerId       = "trigger1"
      status         = "ACTIVE"
      type          = "Remote"
      request_body = "json"
    }
  ]
  elasticsearch_cluster_name   = "my_mskec_cluster"
}
```

This configuration defines an Amazon MSK cluster with encrypted data at rest using Amazon Elasticsearch Service and AWS KMS key. Access policies are defined to allow the users within Elasticsearch IAM role to perform actions. The cluster config is set with data encrypted nodes among other configurations. The Global cluster is provisioned, and endpoint configurations are defined to allow VPC level access to the cluster. The security policies are defined using the certificate IDs of decoding clients. Cross-cluster triggers are defined, allowing for some functionalities over multiple clusters. The cross-cluster triggers are defined over the clients as Remote triggering data nodes.

