provider "aws" {
  region = "us-east-1"
}

resource "aws_msk_cluster" "example_msk_cluster" {
  cluster_name                   = "example-cluster"
  master_identity                 = "arn:aws:iam::123456789012:role/service-role/AmazonMSKNodeInstanceRole"
  broker_node_group_info {
    peer_info {
      security_config_group_mutual_tls {
        tls {
          certificate_authority_arn = aws_iam_server_certificate.example_certificate.arn
        }
      }
    }
    logging_info {
      broker_logs {
        cloud_watch_logs {
          enabled = true
          log_group_arn = aws_cloudwatch_log_group.example_log_group.arn
        }
      }
    }
    encryption_info {
      encryption_in_transit {
        encryption_type = "TLS_1.0"
        kms_key_id = aws_kms_key.example_kms_key.arn
      }
      encryption_at_rest {
        encryption_type = "KMS"
        kms_key_id = aws_kms_key.example_kms_key.arn
      }
    }
    open_monitoring {
      enabled = true
    }
  }
  client_authentication {
    sas {
      enabled = true
      sasl_scram_defaults {
        enabled = true
      }
      sasl_iam_roles {
        sasl_role_arn = aws_iam_role.example_sasl_role.arn
      }
    }
  }
}

resource "aws_cloudwatch_log_group" "example_log_group" {
  name = "/aws/msk/example-cluster"
  retention_in_days = 7
}

resource "aws_kms_key" "example_kms_key" {
  description = "MSK Encryption Key"
  policy = <<POLICY
{
  "Version": "2012-10-17",
  "Id": "key-default-1",
  "Statement": [
    {
      "Sid": "Enable encryption",
      "Effect": "Allow",
      "Principal": { "AWS": "arn:aws:iam::123456789012:root" },
      "Action": "kms:Encrypt",
      "Resource": "arn:aws:kms:us-east-1:123456789012:key/example-key-id"
    }
  ]
}
POLICY
}

resource "aws_kinesis_firehose_delivery_stream" "example_firehose_delivery_stream" {
  name        = "example-firehose-delivery-stream"
  destination_uuid = aws_s3_bucket.example_s3_bucket.bucket
  role_arn     = aws_iam_role.example_firehose_role. arn
  kinesis_arn  = aws_iam_server_certificate.example_kms_key.kinesis_stream_arn
  buffer_size  = 10
  buffer_interval  = 120

  # Ensure proper S3 bucket setup
  dynamic "s3_configuration_credentials" {
    for_each = [aws_iam_role.example_firehose_role]
    content {
      role_arn = aws_iam_role.example_firehose_role.arn
    }
  }
}

resource "aws_s3_bucket" "example_s3_bucket" {
  bucket = "example-logs-bucket"
  acl   = "private"
}

resource "aws_iam_role" "example_firehose_role" {
  name = "example-firehose-role"
  assume_role_policy {
    # Role policy configuration here
  }
}

resource "aws_iam_role" "example_sasl_role" {
  name = "example-SASL-role"
  assume_role_policy {
    # Role policy for SASL authentication
  }
}

