resource "aws_msk_cluster" "msk_cluster" {
  cluster_name               = "my-msk-cluster"
  configuration_info {
    kafka_versions {
      version = "2.1"
    }
    kafka_broker {
      broker_node_group_info {
        broker_node_groupArn = aws_msk_cluster.broker_node_groups.arn
        broker_public_hostname = "my-cluster-node"
      }
    }
    control_plane_security_group_info {
      security_group_id = aws_security_group.msk_control_plane_id.id
    }
    zookeeper_security_group_info {
      security_group_id = aws_security_group.msk_zookeeper_id.id
    }
  }
  security_config_info {
    security_config        = aws_msk_security_config.security_config_content.config
    encryption_info {
      encryption_type = "TLS"
      in_cluster = true
    }
  }
  broker_node_info {
    efs_configuration {
      efs_file_system_id = "my-efs-id"
    }
    software_bitness = "BOTH"
  }
  open_monitoring {
    enabled = true
    customer_tools_endpoint = aws_msk_cluster.broker_public_hostname
  }
}

resource "aws_msk_security_config" "security_config" {
  name         = "security-config"
  description  = "Configuration for encryption at rest"
  kafka_encryption_configuration {
    encryption_type       = "SSL"
    bootstrap_servers    = aws_msk_cluster.broker_public_hostname
    certificate_arn      = aws_msk_cluster.certification.ARNs[0]
    ca_database_identifier = "my-ca"
    ca_password          = "abc123"
  }
  client_authentication {
    sasl = true
    ssl = true
  }
}

