  client_authentication {
    sasl = true
    ssl = true
  }
}

resource "aws_msk_cluster_config" "cluster_config" {
  description       = "cluster-configuration"
  security_config   = aws_msk_security_config.security_config_content.config
  sensitive_analytics_auto_clean_retention_settings {
    auto_clean       = false
    tls_enabled     = true
  }
}

resource "aws_efs_access_point" "debezium" {
  file_system_id   = "your-efs-id" // Your EFS ID
  creator_access_point_id = "debezium"
  root_directory {
    path = "/debezium"
  }
  transit_encryption "NONE" // Your transit encryption setting
}

resource "aws_efs_file_system" "debezium" {
