```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name               = "my-msk-cluster"
  configuration_info {
    kafka_versions {
      version = "2.1"
    }
    kafka_broker {
      broker_node_group_info {
        broker_node_groupArn = aws_msk_cluster.broker_node_groups.arn
        broker_public_hostname = "my-cluster-node"
      }
    }
    control_plane_security_group_info {
      security_group_id = aws_security_group.msk_control_plane_id.id
    }
    zookeeper_security_group_info {
      security_group_id = aws_security_group.msk_zookeeper_id.id
    }
  }
  security_config_info {
    security_config        = aws_msk_security_config.security_config_content.config
    encryption_info {
      encryption_type = "TLS"
      in_cluster = true
    }
  }
  broker_node_info {
    efs_configuration {
      efs_file_system_id = "my-efs-id"
    }
    software_bitness = "BOTH"
  }
  open_monitoring {
    enabled = true
    customer_tools_endpoint = aws_msk_cluster.broker_public_hostname
  }
}

resource "aws_msk_security_config" "security_config" {
  name         = "security-config"
  description  = "Configuration for encryption at rest"
  kafka_encryption_configuration {
    encryption_type       = "SSL"
    bootstrap_servers    = aws_msk_cluster.broker_public_hostname
    certificate_arn      = aws_msk_cluster.certification.ARNs[0]
    ca_database_identifier = "my-ca"
    ca_password          = "abc123"
  }
  client_authentication {
    sasl = true
    ssl = true
  }
}

resource "aws_msk_cluster_config_map" "cluster_config" {
  msk_cluster       = aws_msk_cluster.msisk_cluster.id
  client_authentication {
    sasl = true
    ssl = true
  }
}

resource "aws_msk_cluster_config" "cluster_config" {
  description       = "cluster-configuration"
  security_config   = aws_msk_security_config.security_config_content.config
  sensitive_analytics_auto_clean_retention_settings {
    auto_clean       = false
    tls_enabled     = true
  }
}

resource "aws_efs_access_point" "debezium" {
  file_system_id   = "your-efs-id" // Your EFS ID
  creator_access_point_id = "debezium"
  root_directory {
    path = "/debezium"
  }
  transit_encryption "NONE" // Your transit encryption setting
}

resource "aws_efs_file_system" "debezium" {
  creation_token    = aws_efs_access_point.debezium.creation_token
}

resource "aws_msk_connect_s3_fanout" "connect_s3_fanout" {
  sisk_cluster         = aws_msk_cluster.msisk_cluster.id
  s3_bucket_source_config {
    bucket_name           = aws_s3_bucket.debezium_bucket.bucket
  }
  delivery_configuration {
    delivery_stream_name = aws_msk_connect_s3_fanout.externalse_direct_put.name
  }
}

resource "aws_msk_connect_s3_fanout" "delivery_stream" {
  sisk_cluster         = aws_msk_cluster.msisk_cluster.id
  s3_bucket_source_config {
    bucket_name           = aws_s3_bucket.debezium_bucket.bucket
  }
  delivery_stream {
    delivery_stream    = aws_kinesis_firehose.debezium_delivery_stream.id
    connector_ref_consumer_manifest_data {
    broker {
      broker {
        broker_id = aws_efs_access_point.debezium. While
      }
      connector_settings {
        connector_plugins        = "debezium-connect-plugin"        
        tls_enabled             = "my-plugin-tls"      
        connector_cafile         = "my-plugin-cafile"
      }
    }
  }
}

resource "aws_kinesis_delivery_stream" "kinesis_datafirehose_stream" {
  name              = "my-kinesis-firehose"
  retention_period  = 1
  kinesis_stream {
    name = aws_msk_connect_s3_fanout.delivery_stream.name
  }
  shard_level_bication {
    data_retention = "KILNDATA" //kinesis stream kafka-like retention
  }
}

resource "aws_s3_bucket" "debezium_bucket" {
  bucket = "my-debezium-bucket"
}
```

