provider "google" {
  credentials = file("path/to/service-account-file.json")
  project     = "your-gcp-project-id"
  region      = "your-gcp-region" # e.g., "us-central1"
}

resource "google_sql_database_instance" "mysql-instance" {
  name             = "mysql-instance"
  region           = var.region
  database_version = {
    type  = "MYSQL_5_7"
  }
  settings = {
    tier = "db-custom-1-96"
    # Adjust the tier and storage settings to add 100 GB per zone.
    disk_size_gb = 250
    disk_type   = "PD-HDD"
  }
}

resource "google_sql_database_variant" "mysql-higher-mysql-version" {
  database_instance_id = google_sql_database_instance.mysql_instance.id
  name                = "${google_sql_database_instance.mysql_instance.name}-high-mysql-version"
  database_version   = {
    type  = "MYSQL_5_7"
  }
  settings           = {
    tier = "db-custom-1-96"
    disk_size_gb    = 250
    disk_type       = "PD-HDD"
  }
}

resource "google_sql_database" "mysql-database" {
  name       = "mysql-database"
  instance   = google_sql_database_instance.mysql_instance.name
}

resource "google_sql_database_user" "mysql-user" {
  name       = "mysql-user"
  instance   = google_sql_database_instance.mysql_instance.name
  database   = google_sql_database.mysql_database.name
}

resource "google_sql_database_instance" "mysql-instance-in-az" {
  name = "mysql-instance-in-az1"
  settings {
    tier                    = "db-custom-1-96"
    backup_configuration   = {
      name = "${google_sql_database_instance.mysql_instance.name}-backup"
      binary_log_enabled     = false
    }
    storage_auto_increase = true
    disk_size_gb = 250
  }
}

# Repeat for other zones with different names and potentially different settings
resource "google_sql_database_instance" "mysql-instance-in-az2" {
  name = "mysql-instance-in-az2"
  settings {
    disk_size_gb = 250
    disk_type   = "pd-standard-146"
  }
}

resource "google_sql_database_instance" "mysql-instance-in-az3" {
  name = "mysql-instance-in-az3"
  settings {
    disk_size_gb = 250
    disk_type   = "pd-standard-146"
  }
}

# Usage example - application configuration, using cloud provider's static IP for the read replicas
resource "google_sql_database_instance" "application-instance" {
  name              = "application-instance"
  settings {
    ip_configuration {
      type            = "PRIVATE_INTERNAL"
    }
    disk_size_gb     = 250
    disk_type        = "pd-standard"
  }
  engine_version  = "5.7"
}

# Connect your application to read replicas
resource "google_sql_database_instance" "read-replica-instance" {
  name            = "read-replica-instance"
  settings {
    disk_size_gb   = 100 # Replicas do not need as much Disk space as an instance, in this case, we allocate 100 GB for provisions per replica.
    disk_type      = "pd-ssd"
  }
}

resource "google_sql_database_instance" "write-replica-instance" {
  name            = "write-replica-instance" # Write replicas has special naming
  settings {
    disk_size_gb   = 100
    disk_type      = "pd-ssd"
  }
}

