```hcl
provider "aws" {
  region     = "us-east-1"
  alias     = "primary"
}

provider "aws" {
  region     = "us-west-2"
  alias     = "secondary"
}

resource "aws_vpc" "primary_vpc" {
  provider = aws.primary
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "PrimaryVPC"
  }
}

resource "aws_vpc" "secondary_vpc" {
  provider = aws.secondary
  cidr_block = "11.0.0.0/16"
  tags = {
    Name = "SecondaryVPC"
  }
}

resource "aws_vpc_peering_connection" "vpc_peering" {
  vpc_id      = aws_vpc.primary_vpc.id
  peer_vpc_id  = aws_vpc.secondary_vpc.id
  auto_accept  = true

  provider = aws.primary
}

resource "aws_vpc_peering_connection" "vpc_peering_secondary" {
  vpc_id         = aws_vpc.secondary_vpc.id
  peer_vpc_id     = aws_vpc.primary_vpc.id
  auto_accept     = true

  provider = aws.secondary
}

resource "aws_route" "primary_to_secondary" {
  route_table_id = aws_vpc.primary_vpc.main_route_table_id
  destination_cidr_block = aws_vpc.secondary_vpc.cidr_block

  provider = aws.primary
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peering.id
}

resource "aws_route" "secondary_to_primary" {
  route_table_id = aws_vpc.secondary_vpc.main_route_table_id
  destination_cidr_block = aws_vpc.primary_vpc.cidr_block

  provider = aws.secondary
  vpc_peering_connection_id = aws_vpc_peering_connection.vpc_peering.id
}
```

In this configuration for two VPCs:

1. **`aws_vpc` resources** define the primary and secondary VPC with CIDR blocks.
2. **`aws_vpc_peering_connection` resources** establish peering connections between the primary and secondary VPCs.
3. **`aws_route` resources** configure routes for communication via the peering connections.

Ensure you replace specific values (like regions, CIDR blocks, etc.) with those appropriate to your setup. Adjust tags and other settings as needed to reflect your naming conventions and peering connection details.

