provider "aws" {
  region = "us-east-1" # Specify your desired AWS region
}

resource "aws_db_subnet_group" "neptune_subnet_group" {
  name         = "neptune-subnet-group"
  subnet_ids   = ["subnet-12345678", "subnet-87654321"] # Replace with your actual subnet IDs
}

resource "aws_neptune_cluster_parameter_group" "neptune_custom_params" {
  name = "neptune-custom-param-group"
  family = "neptune2"

  parameter {
    name  = "neptune_enable_features"
    value = "true"
    apply_method = "immediate"
    }

  parameter {
    name  = "neptune_enable_logging"
    value = "disabled"
    apply_method = "immediate"
  }
}

resource "aws_neptune_cluster" "neptune_cluster" {
  cluster_identifier = "neptune-cluster"
  db_cluster_parameter_group = aws_neptune_cluster_parameter_group.neptune_custom_params.name

  engine      = "neptune"
  engine_version = "1.10.2" # Adjust according to your version requirement
  source_db_identifier = "neptune-instance"

  # Define the accessibility from desired subnets
  subnet_settings {
    subnet_identifier = ["subnet-12345678", "subnet-87654321"] # Replace with your actual subnet IDs
  }
}

resource "aws_neptune_cluster_instance" "neptune_instance" {
  count            = 1
  cluster_identifier = aws_neptune_cluster.neptune_cluster.cluster_identifier
  instance_class  = "db.m4.large"
  instance_identifier = "neptune-instance"
  publicly_accessible = false
}

resource "aws_neptune_instance" "neptune_unauthorized_instance" {
  # Use this resource to define an instance which is restricted by the cluster security groups
  node_type = "db.r5.large"
  availability_zone = "us-east-1a" # Adjust to your preferred availability zone

  # Associating security groups that only allow access from specific subnets
  vpc_security_group_ids = [aws_neptune_cluster.neptune_cluster.vpc_security_group_ids] # Add specific security group IDs to restrict unauthorized access
}

resource "aws_security_group" "neptune_cluster_sg" {
  name        = "neptune-cluster-sg"
  description = "Security group for Neptune cluster"

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1" # Allow all outbound traffic
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "all"  # allowing all traffic

    # Restrict inbound access to this security group to internal subnets only
    self = true
  }
}

resource "aws_security_group_rule" "allow_internal_ingress" {
  type              = "ingress"
  from_port         = 8182
  to_port           = 8182
  protocol         = "tcp"
  security_group_id = aws_security_group.neptune_cluster_sg.id

  source_security_group_id = aws_neptune_cluster.neptune_cluster.vpc_security_group_ids[0] # Adjust to specific management subnet
}

resource "aws_security_group_rule" "allow_cluster_ingress" {
  type                       = "ingress"
  from_port                  = 8182 # Adjust according to your requirements
  to_port                    = 8182
  protocol                   = "tcp"
  cidr_blocks                = ["subnet-12345678", "subnet-87654321"] # Allow ingress only from specified subnets

  security_group_id = aws_security_group.neptune_cluster_sg.id
}

