  availability_zone = "us-east-1a" # Adjust to your preferred availability zone

  # Associating security groups that only allow access from specific subnets
  vpc_security_group_ids = [aws_neptune_cluster.neptune_cluster.vpc_security_group_ids] # Add specific security group IDs to restrict unauthorized access
}

resource "aws_security_group" "neptune_cluster_sg" {
  name        = "neptune-cluster-sg"
  description = "Security group for Neptune cluster"

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1" # Allow all outbound traffic
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "all"  # allowing all traffic

    # Restrict inbound access to this security group to internal subnets only
    self = true
  }
}

resource "aws_security_group_rule" "allow_internal_ingress" {
  type              = "ingress"
  from_port         = 8182
  to_port           = 8182
  protocol         = "tcp"
  security_group_id = aws_security_group.neptune_cluster_sg.id

  source_security_group_id = aws_neptune_cluster.neptune_cluster.vpc_security_group_ids[0] # Adjust to specific management subnet
}

resource "aws_security_group_rule" "allow_cluster_ingress" {
  type                       = "ingress"
  from_port                  = 8182 # Adjust according to your requirements
  to_port                    = 8182
  protocol                   = "tcp"
  cidr_blocks                = ["subnet-12345678", "subnet-87654321"] # Allow ingress only from specified subnets

  security_group_id = aws_security_group.neptune_cluster_sg.id
}
```
Note: Replace placeholder subnet and security group IDs with actual ones from your AWS environment and adjust security rules according to your specific network design.

