provider "aws" {
  region = "us-east-1"  # Replace with your desired AWS region
}

resource "aws_s3_bucket" "mybucket" {
  bucket = "mybucket"
  acl    = "private"

  tags = {
    Name = "My S3 Bucket"
  }

  lifecycle {
    prevent_destroy = true
  }

  versioning {
    enabled = true
  }

  intelligent_tiering_configuration {
    tiering_configurations = [
      {
        id                 = "TierOne"
        tierings          = ["ARCHIVE_ACCESS", "DEEP_ARCHIVE_ACCESS"]
        days_for_auto_transition_inversion = 30
        days_for_auto_transition_recovery = 30
        days_for_auto_transition = 7
      }
    ]
  }

  dynamic "cors_rule" {
    for_each = tolist([{
      allowed_methods  = ["GET", "HEAD"]
      allowed_origins   = ["*"]
      exposed_headers  = ["*"]
      max_age_secs      = 3000
    }])
    content {
      cors_rule {
        CORSRule = cors_rule.value
      }
    }

  }
}

