  region = "us-west-2"
}

resource "aws_s3_bucket" "course_s3_bucket" {
  bucket = "cs-course-grading-bucket"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default = true
      server_side_encryption_configuration {
        sse_algorithm         = "AES256"
        bucket_key_enabled    = false
      }
    }
  }

  lifecycle {
    prevent_destroy = false
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "CodeBuildGradingRole"

  assume_role_policy {
    version = "2012-10-17"
    statement {
      effect = "Allow"
      principal {
        service = "codebuild.amazonaws.com"
      }
      action = "sts:AssumeRole"
    }
  }
}

resource "aws_iam_policy" "CodeBuildPermissions" {
  name = "CodeBuildPermissions"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:DeleteObject"
        ]
        Resource = [
          "${aws_s3_bucket.course_s3_bucket.arn}",
          "${aws_s3_bucket.course_s3_bucket.arn}/*"
        ]
      },
      {
        Effect    = "Allow"
        Action   = [
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchCheckLayerAvailability"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn  = aws_iam_policy.CodeBuildPermissions.arn
}

resource "aws_codebuild_project" "grader_codebuild" {
  name          = "CS_HOC_GraderCodeBuildProject"
