```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_s3_bucket" "course_s3_bucket" {
  bucket = "cs-course-grading-bucket"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default = true
      server_side_encryption_configuration {
        sse_algorithm         = "AES256"
        bucket_key_enabled    = false
      }
    }
  }

  lifecycle {
    prevent_destroy = false
  }
}

resource "aws_iam_role" "codebuild_role" {
  name = "CodeBuildGradingRole"

  assume_role_policy {
    version = "2012-10-17"
    statement {
      effect = "Allow"
      principal {
        service = "codebuild.amazonaws.com"
      }
      action = "sts:AssumeRole"
    }
  }
}

resource "aws_iam_policy" "CodeBuildPermissions" {
  name = "CodeBuildPermissions"
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:PutObjectAcl",
          "s3:DeleteObject"
        ]
        Resource = [
          "${aws_s3_bucket.course_s3_bucket.arn}",
          "${aws_s3_bucket.course_s3_bucket.arn}/*"
        ]
      },
      {
        Effect    = "Allow"
        Action   = [
          "ecr:GetDownloadUrlForLayer",
          "ecr:BatchCheckLayerAvailability"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn  = aws_iam_policy.CodeBuildPermissions.arn
}

resource "aws_codebuild_project" "grader_codebuild" {
  name          = "CS_HOC_GraderCodeBuildProject"
  description   = "CS OCC course Grader project"
  source       = "GITHUB"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type             = "BUILD_GENERAL1"
    image                    = "aws/codebuild/standard:5.0"
    environment_variable {
      name  = "GRADE_OUTPUT_BUCKET"
      value = aws_s3_bucket.course_s3_bucket.bucket
    }
  }

  source_selection {
    repo = "FULL_REPOSITORY"
    branch = "master"
  }

  service_role = aws_iam_role.codebuild_role.arn
}
```

The code defines:

1. An AWS S3 bucket to store the submission files and grading outputs.
2. An IAM role that allows AWS CodeBuild to assume the role, necessary for the build project.
3. An IAM policy granting permissions for CodeBuild to interact with S3.
4. A CodeBuild project configured to execute grading operations based on the specified source and environment variables.

The compute environment in AWS CodeBuild is set to `BUILD_GENERAL1`, which is suitable for grading code submissions. Similarly, versioning is enabled on the S3 bucket to protect graded results, ensuring that they aren't accidentally overwritten or deleted. The IAM policy attached to the CodeBuild project restricts access to specific S3 resources and allows online layer checks for container build images. The credentials for S3 interactions should ideally be fetched from GitHub secrets, which aren't included in the above Terraform code, but you should set them in your GitHub repository where the student code submissions and setup files are hosted.

