```hcl
provider "aws" {
  region = "us-west-2" # Change this region as needed
}

resource "aws_vpc" "vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet" {
  vpc_id     = aws_vpc.vpc.id
  cidr_block  = "10.0.1.0/24"
}

resource "aws_security_group" "code_execution_sg" {
  vpc_id = aws_vpc.vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24"] # Allow access only within subnet
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["10.0.1.0/24"] # Restrict egress to local subnet
  }
}

resource "aws_codebuild_project" "student_submissions" {
  name = "student-submissions"

  source {
    type      = "GITHUB"
    location  = "https://github.com/{YOUR_GITHUB_REPO}.git"

    auth {
      type  = "OAUTH"
      resource = "arn:aws:codebuild:us-west-2:000000000000:repository/{YOUR_GITHUB_REPO}"
    }
  }

  environment {
    compute_type = "BUILD_GENERAL1"
    image         = "aws/codebuild/standard:4.0"
    type          = "LINUX"

    environment_variable {
      name  = "NO_INTERNET_ACCESS"
      value = "true"
      type  = "PLAINTEXT"
    }
  }

  service_role = aws_iam_role.codebuild_role.arn
}

resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-execution-role"

  assume_role_policy {
    json = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Action = "sts:AssumeRole"
          Effect = "Allow"
          Principal = {
            Service = "codebuild.amazonaws.com"
          }
      }
    })
  }
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attachment" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn  = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

resource "aws_s3_bucket" "s3_bucket" {
  bucket = "student-submissions-bucket"
  acl    = "private"

  versioning {
    enabled = true
  }
}

resource "aws_s3_bucket_public_access_block" "s3_public_access_block" {
  bucket = aws_s3_bucket.s3_bucket.id
  block_public_acls = true
  ignore_public_acls = true
  block_public_policy = true
  restrict_public_buckets = true
  object_lock_public_access = false
}

# Example configuration for GitHub Actions that triggers AWS CodeBuild on code push
resource "aws_iam_user" "github_user" {
  name = "GitHub-AWS"
}

resource "aws_iam_access_key" "github_access_key" {
  user    = aws_iam_user.github_user.name
  create_with:: {
    policy = "github_policy"
  }
}

data "aws_iam_policy_document" "github_policy" {
  statement {
    actions = [
      "s3:*", 
      "codebuild:StartBuild"
    ]
    resources = [
      "arn:aws:s3:::${aws_s3_bucket.s3_bucket.id}",
    ]
    effect = "Allow"
  }
}

resource "aws_iam_policy" "github_policy" {
  name = "GitHub-CodeBuild-Access"
  policy = data.aws_iam_policy_document.github_policy.json
}

resource "aws_iam_policy_attachment" "github_policy_attachment" {
  name       = "github-codebuild-access"
  user       = aws_iam_user.github_user.name
  policy_arn = aws_iam_policy.github_policy.arn
}
