provider "aws" {
  region = "us-east-1" # Change to your desired region
}

resource "aws_s3_bucket" "build_artifacts" {
  bucket = "my-build-artifacts"
  acl    = "private"
  force_destroy = true
}

resource "aws_vpc" "main_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "main_subnet" {
  vpc_id = aws_vpc.main_vpc.id
  cidr_block = "10.0.0.0/24"
}

resource "aws_security_group" "no_access_sg" {
  vpc_id = aws_vpc.main_vpc.id

  ingress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_codebuild_project" "student_codebuild_project" {
  name        = "StudentCodeBuildProject"
  description = "AWS CodeBuild Project for student build outputs"
  build_spec {
    timeout  = "5"
    type     = "BUILDSPEC_TYPE"
    build_compute_type = "BUILD_GENERAL1_SMALL"
    environment {
      image = "alpine"
      type = "LINUX_CONTAINER"
    }
    artifacts {
      type = "S3"
      location = aws_s3_bucket.build_artifacts.bucket
    }
  }

  source {
    type = "GITHUB"
    auth = "GITHUB" # Assuming GitHub authentication is defined elsewhere
    owner = "github"
    repo = "source-location"
    build_spec = "buildspec.yml"
    webhook = false
    webhook_secret = ""
    report_build_status = false
  }

  vpc_config {
    vpc_id         = aws_vpc.main_vpc.id
    vpc_subnet_ids = [aws_subnet.main_subnet.id]
  }
}
```

Please ensure that the values for authentication and sensitive information like `auth` for the CodeBuild project source hosted on GitHub are set appropriately in your environment. For example, you may want to replace the `"GITHUB"` string with the appropriate GitHub authentication ARN for security purposes. 

Remember to confirm and make any necessary adjustments to the CIDR blocks, location and setup according to your specific AWS region and infrastructure setup.

