provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "cat_images_bucket" {
  bucket = "cat-images-uploadd"
  acl    = "private"

  website {
    index_document = "index.html"
  }

  tags = {
    Name = "Cat Images Bucket"
  }
}

resource "aws_s3_bucket_website" "cat_images_bucket_website" {
  bucket = aws_s3_bucket.cat_images_bucket.id
}

resource "aws_lambda_function" "cat_upload_handler" {
  function_name = "catUploadHandler"
  handler       = "index.handler"
  role          = aws_iam_role.lambda_exec.uer
  runtime       = "nodejs14.x"

  timeout = 120
  source_code_hash = filebase64sha256("lambda.zip")
  environment {
    variables = {
      S3_BUCKET_NAME = aws_s3_bucket.cat_images_bucket.bucket
    }
  }
}

resource "aws_lambda_permission" "cat_upload_lambda_permission" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_upload_handler.function_name
  principal    = "apigateway.amazonaws.com"

  source_arn = aws_api_gateway_rest_api.cat_api_gateway.execution_arn
}

resource "aws_api_gateway_rest_api" "cat_api_gateway" {
  name = "catImageAPI"
}

resource "aws_api_gateway_resource" "cat_image_upload_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api_gateway.id
  parent_id   = aws_api_gateway_rest_api.cat_api_gateway.root_resource_id
  path_part   = "upload"
}

resource "aws_api_gateway_resource" "cat_random_image_resource" {
  rest_api_id = aws_api_gateway_rest_api.cat_api_gateway.id
  parent_id   = aws_api_gateway_resource.cat_image_upload_resource.parent_id
  path_part   = "cats/{id}"
}

resource "aws_api_gateway_method" "cat_upload_method" {
  rest_api_id   = aws_api_gateway_rest_api.cat_api_gateway.id
  resource_id   = aws_api_gateway_resource.cat_image_upload_resource.id
  http_method   = "POST"
  authorization = "NONE"

  api_gateway_integration {
    type        = "AWS"
    uri         = "arn:aws:apigateway:${aws_region}:lambda:path/2015-03-31/functions/${aws_lambda_function.cat_upload_handler.arn}/invocations"
    request_parameters {
      http_method    = "POST"
      integration_http_method = "POST"
      payload_requirements = "-sdk-type=v1.0"
    }

    integration_responses {
      http_status_code    = "200"
      response_parameters = { "method" = "POST" }
      curl = "true"
    }
  }
}

resource "aws_api_gateway_method" "cat_random_image_method" {
  rest_api_id  = aws_api_gateway_rest_api.cat_api_gateway.id
  resource_id   = aws_api_gateway_resource.cat_random_image_resource.id
  http_method   = "GET"
  authorization = "NONE"

  request_parameters {
    querystrings = [
      { "name" = "id", "value" = "${aws_api_gateway_integration.response_data(HTTP_200)" }
    ]
  }

  integration {
    type       = "MOCK"
    http_method = "GET"
    payload   = "catId"

    integration_response {
      type        = "MOCK"
      selection_pattern = "cats/{id}"
      http_status_code = "200"
    }

    mock_integration {
      request_templates {
        "application/json": "{"statusCode": 200}"
      }
    }
  }
}

resource "aws_cloudfront_distribution" "cat_static_bak" {
  origin {
    domain_name       = aws_s3_bucket.cat_images_bucket.domain_name
    origin_id         = "S3-${aws_s3_bucket.cat_images_bucket.name}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.cat_static_bucket.origin_access_identity_id
    }
  }

  aliases = [{
    name = aws_api_gateway_domain_name.cat_api_domain.cloudfront_domain_name
  }]
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}


provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_dynamodb_table" "caas" {
  name           = "cat_names"
  hash_key       = "name"
  billing_mode   = "PAY_PER_REQUEST"

  attribute {
    name = "name"
    type = "S"
  }
}

resource "aws_s3_bucket" "caas" {
  bucket_prefix = "cat-image"
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_api_gateway_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_policy" {
  name   = "lambda_policy"
  role   = aws_iam_role.lambda_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Effect   = "Allow"
        Resource = "${aws_s3_bucket.caas.arn}/*"
      },
      {
        Action = [
          "dynamodb:PutItem"
        ]
        Effect   = "Allow"
        Resource = aws_dynamodb_table.caas.arn
      }
    ]
  })
}

resource "aws_api_gateway_rest_api" "caas" {
  name = "caas"
}

resource "aws_api_gateway_resource" "caas_cat" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  parent_id   = aws_api_gateway_rest_api.caas.root_resource_id
  path_part   = "cat"
}

resource "aws_api_gateway_method" "caas_cat_get" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_method" "caas_cat_put" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "PUT"
  authorization = "NONE"
}

data "archive_file" "caas_cat" {
  type        = "zip"
  source_file = "./supplement/caas_cat.py"
  output_path = "./supplement/caas_cat.zip"
}

resource "aws_lambda_function" "caas_cat" {
  function_name = "caas_cat"
  role          = aws_iam_role.lambda_role.arn
  filename      = data.archive_file.caas_cat.output_path
  source_code_hash = data.archive_file.caas_cat.output_base64sha256
  handler       = "caas_cat.handler"
  runtime       = "python3.12"

  environment {
    variables = {
      CAAS_S3_BUCKET = "${aws_s3_bucket.caas.id}"
      DYNAMODB_TABLE_NAME = "${aws_dynamodb_table.caas.id}"
    }
  }
}

resource "aws_api_gateway_integration" "caas_cat_get" {
  rest_api_id             = aws_api_gateway_rest_api.caas.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_cat_get.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "GET"
  uri                     = aws_lambda_function.caas_cat.invoke_arn
}

resource "aws_api_gateway_integration" "caas_cat_put" {
  rest_api_id             = aws_api_gateway_rest_api.caas.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_cat_put.http_method
  type                    = "AWS_PROXY"
  integration_http_method = "PUT"
  uri                     = aws_lambda_function.caas_cat.invoke_arn
}

resource "aws_lambda_permission" "caas_cat" {
  action        = "lambda:InvokeFunction"
  principal     = "apigateway.amazonaws.com"
  function_name = aws_lambda_function.caas_cat.function_name

  source_arn = "${aws_api_gateway_rest_api.caas.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "api_deployment" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  depends_on  = [aws_api_gateway_integration.caas_cat_get, 
                 aws_api_gateway_integration.caas_cat_put]
}

resource "aws_api_gateway_stage" "api_stage" {
  deployment_id = aws_api_gateway_deployment.api_deployment.id
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  stage_name    = "dev"
}

output "api_id" {
  value = aws_api_gateway_rest_api.caas.id
  description = "The API Gateway ID"
}

