provider "aws" {
  region = "us-east-1" # You can change this to your preferred AWS region
}

resource "aws_s3_bucket" "cats_bucket" {
  bucket = "unique-cat-images-bucket-${random_string.bucket.result}"
  acl    = "private"
}

resource "random_string" "bucket" {
  length  = 6
  special = false
}

resource "aws_lambda_function" "upload_lambda" {
  function_name = "uploadCatImages"
  s3_bucket     = aws_s3_bucket.cats_bucket.bucket
  s3_key        = "upload_lambda_function.zip"

  handler       = "index.handler"
  runtime       = "nodejs14.x"
  role          = aws_iam_role.lambda_role. penaute 
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_policy_attachment" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecution"
}

resource "aws_api_gateway_rest_api" "cats_api" {
  name = "CatImagesApi"
}

resource "aws_api_gateway_integration" "cats_images_integration" {
  rest_api_id = aws_api_gateway_rest_api.cats_api.id
  resource_id  = aws_api_gateway_method.cats_images_resource.id
  http_method  = "POST"
  type         = "AWS"
  uri         = aws_lambda_function.upload_lambda.invoke_arn
  integration_http_method = "POST"
  connection_type    = "aws_arn"
}

resource "aws_api_gateway_rest_resource" "cats_images_resource" {
  rest_api_id  = aws_api_gateway_rest_api.cats_api.id
  parent_id     = aws_api_gateway_rest_api.cats_api.root_resource_id
  path_part    = "cats"
}

resource "aws_api_gateway_method" "cats_images_post_method" {
  rest_api_id   = aws_api_gateway_rest_api.cats_api.id
  resource_id    = aws_api_gateway_rest_resource.cats_images_resource.id
  http_method    = "POST"
  authorization = "NONE"

  request_parameters = {
    "method.request.header.Content-Type" = {
      rest_api_id = aws_api_gateway_rest_api.cats_api.id
      default_value = "?./.?."
      required      = true
    },
    "method.request.querystring"] = "catName"
  }
}

resource "aws_api_gateway_resource_policy" "cats_images_policy" {
  rest_api_id   = aws_api_gateway_rest_api.cats_api.id
  resource_id    = aws_api_gateway_rest_resource.cats_images_resource.id
  statement     = [
    {
      Effect     ="Allow"
      Principal  = ["*"]
      Action     = ["glb:execute-api:POST:/cat/*/cats/"]
      Id         = null
    },
  ]
}

resource "aws_api_gateway_deployment" "cats_api_deployment" {
  rest_api_id = aws_api_gateway_rest_api.cats_api.id
  stage_name   = "v1"
}

resource "aws_api_gateway_stage" "cats_api_stage" {
  rest_api_id = aws_api_gateway_rest_api.cats_api.id
  deployment_id = aws_api_gateway_deployment.cats_api_deployment.id
  stage_name   = "cats"
}

