  name = "EC2_Backup_Role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          Service = "backup.amazonaws.com"
        },
        Action = "sts:AssumeRole"
      },
    ]
  })
}

resource "aws_iam_role_policy" "backup_policy" {
  name = "EC2_Backup_Policy"
  role = aws_iam_role.backup_role.id

