provider "aws" {
  region = "us-east-1" # adjust region as needed
}

resource "aws_lambda_function" "lambda_function" {
  function_name    = "CodeExecutionLambda"
  handler         = "index.handler"
  role            = aws_iam_role.lambda_role.arn
  runtime        = "python3.8"

  # Example lambda_handler code
  filename     = "lambda_function.py"
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_policy" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_cloudwatch_event_rule" "event_bridge_rule" {
  name        = "event_bridge_rule"
  schedule_expression = "cron(0 7 * * * ?)" # 07:00 UTC daily
}

resource "aws_cloudwatch_event_target" "event_bridge_target" {
  rule      = aws_cloudwatch_event_rule.event_bridge_rule.name
  arn      = aws_lambda_function.lambda_function.arn
}

resource "aws_iam_role_policy" "cloudwatch_policy" {
  role   = aws_iam_role.cloudwatch_role.name
  policy  = file("${path.module}/cloudwatch_event_policy.json")
}

data "aws_iam_policy_document" "cloudwatch_policy" {
  statement {
    effect    = "Allow"
    actions   = ["logs:CreateLogGroup", "logs:CreateLogStream"]
    resources = ["*"]
  }
}

resource "aws_iam_role" "cloudwatch_role" {
  name = "CloudWatchRole"

  assume_role_policy = data.aws_iam_policy_document.cloudwatch_policy.json
}

resource "aws_lambda_permission" "allow_cloudwatch" {
  action        = "lambda:InvokeFunction"
  function     = aws_lambda_function.lambda_function.function_name
  principal   = "events.amazonaws.com"
  source_arn  = aws_cloudwatch_event_rule.event_bridge_rule.arn
}

# Ensure there is a Python Lambda handler script and the necessary CloudWatch policies in place.

