  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_lambda_function" "lambda_function" {
  function_name = "my_lambda_function"
  description   = "Lambda function for executing code"
  handler      = "index.handler"
  role         = aws_iam_role.lambda_role.arn
  runtime     = "python3.8"

  filename = "path/to/your/function.zip"
  source_code_hash = filebase64sha256("path/to/your/function.zip")
}

resource "aws_lambda_permission" "lambda_permission" {
  statement_id = "allow_eventbridge"
  action       = "lambda:InvokeFunction"
  function_name = aws_lambda_function.lambda_function.function_name
  principal   = "events.amazonaws.com"
  source_arn  = "arn:aws:events:region:account-id:custom-event-bus/default-bus"
}

resource "aws_cloudwatch_event_rule" "eventbridge_rule" {
  name                = "daily_event_rule"
  description         = "EventBridge Rule for daily event"
  event_pattern      = jsonencode({
    source      = ["aws.ec2"]
    detail_type = ["EC2InstanceStatusChangeNotification"]
  })
  schedule_expression = "rate(1 day)"
}

resource "aws_cloudwatch_event_target" "eventbridge_target" {
  rule      = aws_cloudwatch_event_rule.eventbridge_rule.name
  arn      = aws_lambda_function.lambda_function.arn
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_cloudwatch_event_rule" "cron" {
  schedule_expression = "cron(0 7 * * ? *)"

  role_arn = aws_iam_role.cron.arn
}

resource "aws_cloudwatch_event_target" "cron" {
  rule = aws_cloudwatch_event_rule.cron.name
  arn  = aws_lambda_function.cron.arn
}

data "archive_file" "lambda-func" {
  type        = "zip"
  source_file = "./supplement/lambda_func.py"
  output_path = "./supplement/lambda_func.zip"
}

resource "aws_lambda_function" "cron" {
  function_name = "cron-lambda-function"
  role          = aws_iam_role.cron.arn
  filename      = data.archive_file.lambda-func.output_path
  source_code_hash = data.archive_file.lambda-func.output_base64sha256
  handler       = "lambda_func.handler"
  runtime       = "python3.12"
}

resource "aws_lambda_permission" "cron" {
  function_name = aws_lambda_function.cron.function_name
  action        = "lambda:InvokeFunction"
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.cron.arn
}

data "aws_iam_policy_document" "cron_assume_role" {
  statement {
    actions = ["sts:AssumeRole"]
    principals {
      type = "Service"
      identifiers = [
        "lambda.amazonaws.com",
        "events.amazonaws.com"
      ]
    }
  }
}

resource "aws_iam_role" "cron" {
  name               = "cron_assume_role"
  assume_role_policy = data.aws_iam_policy_document.cron_assume_role.json
}

resource "aws_iam_role_policy_attachment" "cron" {
  role       = aws_iam_role.cron.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

