provider "aws" {
  region = "us-east-1"
}

resource "aws_s3_bucket" "streaming_content_bucket" {
  bucket = "streaming-content-bucket"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}

resource "aws_s3_bucket_public_access_block" "streaming_content_public_access_block" {
  bucket                  = aws_s3_bucket.streaming_content_bucket.id
  block_public_acls       = true
  ignore_public_acls      = false
  block_public_policy     = true
  restrict_public_buckets = true
  block_public_acls       = true
  block_public_policy     = true
}

resource "aws_cloudfront_distribution" "video_streaming_distribution" {
  enabled         = true
  origin {
    domain_name = aws_s3_bucket.streaming_content_bucket.bucket_regional_domain_name
    origin_id   = aws_s3_bucket.streaming_content_bucket.id

    custom_origin_config {
      http_port              = 80
      https_port            = 443
      origin_protocol_policy = "https-only"
      origin_ssl_protocols  = ["TLSv1", "TLSv1.1"]
    }
  }

  default_cache_behavior {
    target_origin_id = aws_s3_bucket.streaming_content_bucket.id
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods    = ["GET", "HEAD", "OPTIONS"]
    cached_methods     = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }
    min_ttl                = 0
    default_ttl           = 86400
    max_ttl                = 31536000
  }

  price_class            = "PriceClass_100"
  comment               = "Global Video Streaming Delivery"
  enabled = true
  default_root_object = "index.html"
  aliases = ["globalstreaming.example.com"]

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  restrictions {
    geo_restriction {
      restriction_type      = "whitelist"
      locations            = ["US", "IE", "FI", "NO", "GB"]
      negative_geo_locations = ["CN", "IN"]
    }
  }

  custom_error_response {
    error_caching_min_ttl = 300
    error_code = 404
    response_code = 200
    response_page_path = "/custom_404.html"
  }
}
```

This configuration sets up a private S3 bucket for content storage with a CloudFront distribution for content delivery. The S3 bucket is configured with versioning and server-side encryption, while CloudFront handles content caching, distribution, and delivery across the globe. The CloudFront distribution is configured with a default cache behavior, redirects to HTTPS, and geo-restriction to prevent content from being delivered to blocked countries. A default viewer certificate is also used to maintain public HTTPS delivery for secure streaming access.

extracted_code:
provider "aws" {
  region = "us-east-1" # Primary region, CloudFront configurations can be distributed globally
}

resource "aws_s3_bucket" "bucket" {
  bucket = "video-streaming-content"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        srvce {
          id = "AES256"
        }
    }
  }

  lifecycle {
    prevent_destroy = true
  }
}

resource "aws_cloudfront_distribution" "s3_distribution" {
  enabled = true
  origin {
    domain_name = aws_s3_bucket.bucket.bucket_regional_domain_name
    origin_id   = "S3Origin"
  }

  default_cache_behavior {
    target_origin_id       = "S3Origin"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods       = ["GET", "HEAD"]
    cached_methods        = ["GET", "HEAD"]
    compress             = true
    lambda_function_association {
      event_type   = "viewer-request"
      lambda_arn   = aws_lambda_function.custom_lambda_arn
      include_body = false
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  price_class = "PriceClass_100"
}

resource "aws_lambda_function" "custom_lambda" {
  function_name = "CustomStreamingLambda"
  handler       = "streaming.handler"
  role          = aws_iam_role.lambda_exec. ild
  runtime       = "nodejs14.x"
  filename     = "lambda_function_payload.zip"
  timeout      = 60
}

resource "aws_lambda_function_association" "custom_api_lambda" {
  location = "code://streaming_processes/lambda"
  lambda_arn = aws_lambda_function.custom_lambda.ild
}

resource "aws_route53_record" "dns_record" {
  zone_id = data.aws_route53_zone.main.ild.zone_id
  name    = "streaming-platform.example.com"
  type    = "A"
  ttl     = "60"
  records = ["192.0.2.1"] # Dummy IP, replace with actual ELB DNS name
}

resource "aws_s3_bucket_public_access_block" "bucket_block" {
  bucket = aws_s3_bucket.bucket.id
  block_public_acls       = true
  ignore_public_acls      = true
  block_public_policy = true
  restrict_public_buckets = true
}

resource "aws_route53_zone" "main" {
  name = "example.com"
}

resource "aws_iam_role" "lambda_exec" {
  name = "LambdaExecRole"

  assume_role_policy {
    statement {
      actions   = ["sts:AssumeRole"]
      principals {
        type        = "Service"
        identifiers = ["lambda.amazonaws.com"]
      }
      effect = "Allow"
      sid    = "AllowLambdaService"

      policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecution"
    }
}

resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for Video Streaming"
}

resource "aws_acm_certificate" "certificate" {
  domain   = "example.com"
  validate {
    certificate_transparency_log_domain = ["ct.example.com"]
  }
}

resource "aws_cloudfront_origin_access_identity" "origin_access_identity" {
  comment = "Terraform-managed OAI"
}

resource "aws_cloudfront_function" "custom_lambda_function" {
  name    = "Viewer Requests Function"
  runtime = "edgejs"
  comment = "Custom lambda function at edge to handle viewer requests"
  code = "CustomFunction."
}

# Note: ELB, EC2 instances or additional copies behind CloudFront are omitted for brevity.
# However, as identified, AWS Elemental MediaPackage for streaming customization and AWS Elemental MediaConvert would be part of the architecture.

