provider "aws" {
  region = "us-east-1" # Example region
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public" {
  vpc_id                  = aws_vpc.main.id
  cidr_block               = "10.0.1.0/24"
  map_public_ip_on_launch  = true
}

resource "aws_subnet" "private" {
  vpc_id         = aws_vpc.main.id
  cidr_block      = "10.0.2.0/24"
  availability_zone = "us-east-1a" # Example AZ
}

resource "aws_internet_gateway" "gateway" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "public" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id  = aws_internet_gateway.gateway.id
  }
}

resource "aws_route_table_association" "public-association" {
  subnet_id      = aws_subnet.public.id
  route_table_id = aws_route_table.public.id
}

resource "aws_security_group" "sg" {
  name        = "sg-video-streaming"
  description = "Security group for video streaming platform"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol   = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port       = 443
    protocol     = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol   = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_instance" "ec2" {
  ami              = "ami-0c55b159cbfafe1fe" # Example AMI ID
  instance_type    = "t2.micro" # Example instance type
  key_name        = "keypair-name"
  vpc_security_group_ids = [aws_security_group.sg.id]
  subnet_id = aws_subnet.public.id

  tags = {
    Name = "VideoStreamingServer"
  }
}

resource "aws_lb" "example" {
  name               = "example-lb"
  internal          = false
  load_balancer_type = "application"
  scheme             = "internet-facing"

  subnets = [
    aws_subnet.public.id,
  ]

  security_groups = [aws_security_group.sg.id]
}

resource "aws_lb_target_group" "tg" {
  name     = "video-content-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.main.id

  health_check {
    interval            = 30
    healthy_threshold  = 3
    unhealthy_threshold = 3
    timeout             = 5
    path               = "/"
    port               = 80
  }
}

resource "aws_lb_listener" "front-end" {
  load_balancer_arn = aws_lb.example.arn
  port              = 80
  protocol         = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}

resource "aws_route53_zone" "main_zone" {
  name = "example.com"
  comment = "Primary DNS Zone"
}

resource "aws_route53_record" "lb_alias" {
  zone_id = aws_route53_zone.main_zone.zone_id
  name    = "video"
  type    = "A"
  records = [
    {
      value = aws_lb.example.dns_name
    }
  ]
  ttl     = 60
}
