provider "google" {
  project = "<YOUR_PROJECT_ID>"
  region  = "<YOUR_REGION>"
}

resource "google_compute_network" "vpc_network" {
  name                  = "vpc-network"
  auto_create_subnetworks = false
}

resource "google_compute_global_address" "global_addr" {
  name          = "global-address"
  purpose      = "VPC_PEERING"
  address      = "IPv4GlobalAddress"
}

resource "google_compute_subnetwork" "public_subnet" {
  name          = "public-subnet"
  ip_cidr_range = "10.0.1.0/24"  // Ensure this range doesn't conflict with your peering setup
  region        = "us-central1"
  network      = google_compute_network.vpc_network.id
  private_ip_google_access    = "private.googleapis.com"
  private_ip_version          = "IPV4"
}

resource "google_sql_database_instance" "postgres_instance" {
  name                 = "dolphinscheduler"
  region               = "us-central1"
  database_version     = "POSTGRES_17"
  settings {
    tier               = "db-custom-5-2880"  // Instance type matching 5GB storage
    database_version  = "POSTGRES_17"
    disk_size          = 10
    disk_type         = "PD_SSD"

    ip_configuration {
      name                   = "dolphinscheduler-ip-configuration"
      ipv4_enabled          = true
      authorized_gae_credentials = [
        {
          gmail_address = "<AUTHORIZED_ACCOUNT>"
          name         = "authorize-gae-credentials"
        }
      ]
      authorized_networks    = [
        google_compute_global_address.global_addr.address,
        google_compute_global_address.global_addr.name,
        google_compute_global_address.global_addr.self_link
      ]
    }

    deletion_protection   = false  # Disabling deletion protection for final snapshot
  }
}

