extracted_code:
provider "google" {
  project = var.project_id
  region  = var.region
}

variable "project_id" {
  description = "The Google Cloud project ID."
  type        = string
}

variable "region" {
  description = "The region for the GCP resources."
  type        = string
}

variable "mysql_db_password" {
  description = "The MySQL database password."
  type        = string
}

resource "google_compute_network" "vpc_network" {
  name = "my-vpc"
}

resource "google_compute_subnetwork" "public_subnet" {
  name          = "public-subnet"
  ip_cidr_range = "10.1.0.0/16"
  region        = var.region
  network      = google_compute_network.vpc_network.id
  enable_flow_logs = true
}

resource "google_compute_subnetwork" "db_access_only_subnet" {
  name          = "db-access-subnet"
  ip_cidr_range = "10.1.1.0/24"
  region        = var.region
  network       = google_compute_network.vpc_network.id
  private_ip_google_access = false

  # Public routes for the public subnet
  ip_cidr_range = "10.1.0.0/16"
}

resource "google_service_networking_connection" "private_vpn_connection" {
  network                 = google_compute_network.vpc_network.id
  service                = "servicenetworking.googleapis.com"
}

resource "google_cloud_sql_instance" "mysql_instance" {
  name          = "my-mysql-instance"
  database_version = "MYSQL_8_4"
  region         = var.region

  settings {
    tier  = "db-n1-standard-5"
    ip_configuration {
      ipv4_enabled = true
      ipv4_cidr_blocks = ["10.1.1.0/24"]
    }
  }

  database {
    instance_class    = "db-n1-standard-5"
    name             = "my-8-4-mysql-db"
    database_version = "MYSQL_8_4"
    region           = var.region
  }

  ip_configuration {
    ipv4_enabled    = true
    private_network = google_compute_subnetwork.public_subnet.id
  }

  master_network_configuration {
    tier             = "db-n1-standard-5"
    ip_configuration {
      ipv4_enabled    = true
      ip_address      = "10.1.1.0"
    }
  }

  authorized_networks {
    network         = google_compute_subnetwork.db_access_only_subnet.id
    instance         = "iap"
    type             = "ONE_TIME"
  }
  authorized_networks {
    network         = google_compute_subnetwork.public_subnet.id
    instance         = "probe"
    type             = "ONE_TIME"
  }
}

resource "google_cloud_sql_region_instance" "sql_region_instance" {
  region             = var.region
  name              = "my-mysql-instance"
  master_instance    = google_cloud_sql_instance.mysql_instance.id
  replica_instances {
    name = google_cloud_sql_instance.mysql_instance.id
    }
}

output "vpc_network" {
  value = google_compute_network.vpc_network.id
}

output "subnets" {
  value = [
    google_compute_subnetwork.public_subnet.id,
    google_compute_subnetwork.db_access_only_subnet.id,
  ]
}

output "mysql_instance" {
  value = google_cloud_sql_instance.mysql_instance.name
}

