provider "aws" {
  region = "us-west-2"
}

resource "aws_kms_key" "my_key" {
  description = "KMS key for PostgreSQL RDS encryption"
}

resource "aws_db_subnet_group" "my_db_subnet_group" {
  name        = "my-db-subnet-group"
  subnet_ids  = ["subnet-0bb1c79b3c491EXAMPLE1", "subnet-0bb1c79b3c491EXAMPLE2"]
}

resource "aws_security_group" "postgres_security_group" {
  name        = "PostgresSecurityGroup"
  description = "Allow inbound traffic to PostgreSQL database"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.1/32"] # Replace with the appropriate CIDR for access control
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1" # Allow all outbound traffic
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_parameter_group" "my_db_parameter_group" {
  name   = "my-postgres-parameters"
  family = "10" # Family for PostgreSQL 12

  parameters = {
    parameter   = "rds.logical_processing_power"
    value      = "5"
    allowed_values = ["5", "10", "20"]
    apply_method = "immediate"
  }

  parameter {
    parameter = "superuser_reserved_connections"
    value     = "12"
    allowed_values = ["1", "10"]
    apply_method = "immediate"
  }
}

resource "aws_db_instance" "postgres_rds_instance" {
  allocated_storage    = 20
  db_instance_class   = "db.t3.micro"
  engine              = "postgres"
  engine_version      = "12.5"
  db_name            = "mydatabase"
  username           = "postgres"
  password           = aws_secretsmanager_secret_version.version
  multi_az           = true
  vpc_security_group_ids = [aws_security_group.PostgresSecurityGroup.id]
  db_subnet_group_name = aws_db_subnet_group.my_db_subnet_group.name
  parameter_group_name = aws_db_parameter_group.my_db_parameter_group.name
  backup_retention_period = 7
  storage_encrypted = true
  kms_key_id = aws_kms_key.my_key.key_id

  publicly_accessible = false
}

data "aws_secretsmanager_secret" "postgres_secret" {
  arn = "arn:aws:secretsmanager:us-west-2:1234567890:secret:mysecretname-ABCD1234"
}

data "aws_secretsmanager_secret_version" "postgres_secret_version" {
  secret_id = data.aws_secretsmanager_secret.postgres_secret.id
  create_before_date = data.aws_secretsmanager_secret.postgres_secret.version_created_date
}

resource "aws_security_group" "postgres_security_group" {
  name        = "postgres-security-group"
  vpc_id      = "vpc-0bb1a78f"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_instance.security_group.id]
  }
}
```
Note: Replace placeholders (like `subnet-0bb1c79b3c491EXAMPLE1`) with appropriate values and ensure that the secret ARN from AWS Secrets Manager is correct.

