  name        = "DatabaseSecurityGroup"
  description = "Allow MySQL database traffic"
  vpc_id     = aws_vpc.primary_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Database SG"
  }
}

resource "aws_rds_instance" "mysql_instance" {
  allocated_storage      = 20
  engine               = "mysql"
  engine_version       = "8.0.19"
  instance_class       = "db.t2.micro"
  availability_zone    = "us-west-2c"
  db_name             = "mydb"
  username            = "admin"
  password            = "securepassword"
  parameter_group_name = "default.mysql8-0-19"
  security_group_ids   = [aws_security_group.database_sg.id]
  vpc_security_group_ids= [aws_security_group.database_sg.id]
}

resource "aws_db_subnet_group" "subnet_group" {
  name        = "mysubnetgroup"
  subnet_ids   = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]
}

resource "aws_rds_cluster_instance" "cluster_instance" {
  cluster_identifier = "mycluster"
  id                = "${aws_rds_cluster.mycluster-master.id}"
  engine              = "mysql"
  engine_version     = "8.0.19"
  instance_class     = "db.t2.medium"
  database_name      = mysql_db_instance.name
  username            = "clusteruser"
  password            = "clusterpass"
}

output "rds_instance_endpoint" {
  value = aws_rds_instance.mysql_instance.endpoint
}

