  description = "Security group for RDS in VPC"
  vpc_id     = aws_vpc.this.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = ["db-security-group"]
  }

  egress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
  }
}

resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier     = "aurora_cluster"
  engine                = "aurora-mysql"
  database_name         = "mydb"
  master_password      = "some-secure-password"
  master_username      = "masteruser"
  storage_encrypted    = true
  skip_final_snapshot  = true
  db_subnet_group_name  = aws_db_subnet_group.this.name
  vpc_security_group_ids = [aws_security_group.rds_security_group.id]
  backup_retention_period = 5
  preferred_backup_window  = "07:00-09:00"
}

resource "aws_db_subnet_group" "this" {
  name       = "my-db-subnet-group"
  subnet_ids  = [aws_subnet.this.id, aws_subnet.this.id]

  tags = {
    Name = "my-db-subnet-group"
  }
}

resource "aws_rds_cluster_parameter_group" "this" {
  name         = "aurora-cluster-parameter-group"
  parameter {
    name         = "binlog_format"
    value       = "ROW"
    apply_method = "pending"
  }
  parameter {
    name         = "binlog retention hours"
    value       = 24
    apply_method = "pending"
  }
}

resource "aws_rds_cluster_instance" "cluster_instance" {
  count                      = 2
  identifier                = "aurora-cluster-instance"
  weight                    = 0
  engine                   = "aurora-mysql"
  engine_version           = "5.7.12"
  engine_mode              = "provisioned"
  db_security_groups       = [aws_security_group.rds_security_group.name]

  instance_class           = "db.r5.large"
  db_parameter_group_name  = aws_rds_cluster_parameter_group.this.name
}

resource "aws_secretsmanager_secret" "my_rds_secret" {
  name         = "my-rds-secret"
  description  = "AURORA DB secret for ${aws_rds_cluster.aurora_cluster.name}"
}

resource "aws_secretsmanager_secret_version" "secret_version" {
  secret_id         = aws_secretsmanager_secret.my_rds_secret.id
  secret_string     = "{"username":"masteruser","password":"some-secure-password"}"
}

resource "aws_db_security_group" "this" {
  name         = "db-security-group"
}

resource "aws_security_group" "db_security_group" {
  name = aws_db_security_group.this.name
}

resource "aws_rds_cluster_parameter_group" "this" {
  name = aws_db_security_group.this.name
}

resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier = "my-aurora-cluster"
  master_password    = data.aws_secretsmanager_secret_version.secret_string
  master_username    = data.aws_secretsmanager_secret_version.secret_string
  cluster_parameter_group_name = aws_db_security_group.this.id
}

resource "aws_rds_db_cluster_parameter_group" "this" {
  name         = "my-rds-db-cluster-param-group"
  family       = "aurora-mysql"
  description  = "Aurora MySQL DB Cluster Parameter Group"
}

resource "aws_rds_cluster_instance" "aurora-db-cluster-name" {
  cluster_identifier = aws_rds_cluster.aurora_cluster.id
  count             = 2
  instance_class    = "db.r5.large"
  db_parameter_group_name = aws_rds_cluster_parameter_group.this.name
}

# Creation of a proxy for handling connections
resource "aws_rds_cluster_database" "aurora-db-clients" {
  cluster_identifier = aws_rds_cluster.aurora_cluster.name
  db_cluster_parameter_name = "my-rds-db-cluster-param-group"

  parameter_group_name = "aurora-rds-parameter-group"
  parameter {
    name = "CLUSTER_PARAMETER_GROUP"
    value = aws_rds_cluster_parameter_group.this.id
  }
}

resource "aws_rds_cluster_instance" "proxy" {
  cluster_identifier = aws_rds_cluster.aurora_cluster.id
  instance_identifier = "ProxyInstance"
}

resource "aws_rds_cluster_parameter_group" "this" {
  parameter {
    name = "MAX_AURORA_CONNECTIONS"
    value = 95 # Aurora cluster max connections value
  }
}

resource "aws_rds_cluster" "db" {
  identifier            = "aurora-cluster"
  database_name         = "default"
  master_username       = "dbmasteruser"
  master_password       = "default"
  db_parameter_group_name = aws_rds_cluster_parameter_group.this.name
}

resource "aws_rds_cluster_instance" "this" {
  identifier = "db"
  count               = 1
  instance_class       = "db.r5.large"
  engine              = "aurora-mysql"
  engine_version      = "5.7.12"
  db_subnet_group_name = "aurora-db-subnet-group"
  db_parameter_group_name = aws_rds_cluster_parameter_group.this.name
  apply_immediately = true
  availability_zone = aws_subnet.subnets.availability_zones[0]
  db_security_groups = [aws_rds_cluster_database.aurora_db_cluster.name]
}

resource "aws_iam_role" "this" {
  assume_role_policy {
    name = "RDSAssumeRole"
    statement = {
      actions = ["sts:AssumeRole"]
      effect  = "Allow"
      principals = {
        type = "Service"
        identifiers = ["rds.amazonaws.com"]
      }
    }
  }
}

resource "aws_vpc_security_group" "rds_sg" {
  vpc_id = aws_vpc.this.id
  security_group_id = "db_cluster_group"
  ingress = {
    from_port   = var.my_db_sg_instance
    to_port     = var.my_db_sg_instance
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress = {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
  }
}

resource "aws_rds_cluster_instance" "db_resource" {
  rds_resource_identifier {
    name = aws_vpc_security_group.rds_sg.name
    identifier = aws_vpc_security_group.rds_sg.id
  }
}

# optional: add tags to the db cluster
resource "aws_rds_cluster_instance" "this" {
  tags = {
    Name = "myDBresource"
  }
}
