provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main"
  }
}

resource "aws_subnet" "subnet1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-west-2a"
  tags = {
    Name = "subnet1"
  }
}

resource "aws_subnet" "subnet2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-west-2b"
  tags = {
    Name = "subnet2"
  }
}

resource "aws_db_subnet_group" "default" {
  name       = "my-db-subnet-group"
  subnet_ids = [aws_subnet.subnet1.id, aws_subnet.subnet2.id]
  tags = {
    Name = "My DB Subnet Group"
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow traffic to RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_rds_cluster" "aurora" {
  cluster_identifier      = "aurora-cluster-demo"
  engine                  = "aurora-mysql"
  engine_version          = "5.7.mysql_aurora.2.07.2"
  database_name           = "mydb"
  master_username         = "admin"
  master_password         = "yoursecurepassword"
  replicate_source_cluster = ""
  db_subnet_group_name    = aws_db_subnet_group.default.name
  vpc_security_group_ids  = [aws_security_group.rds_sg.id]
  skip_final_snapshot     = false
  deletion_protection     = false

  final_snapshot_identifier = "snapshot"
}

resource "aws_secretsmanager_secret" "db_credentials" {
  name        = "DBCredentials"
  description = "Aurora DB credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials_version" {
  secret_id     = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = "yoursecurepassword"
  })
}

resource "aws_rds_cluster_instance" "aurora_instances" {
  count               = 2
  identifier          = format("aurora-instance-%d", count.index)
  cluster_identifier  = aws_rds_cluster.aurora.id
  engine              = "aurora-mysql"
  engine_version      = "5.7.mysql_aurora.2.07.2"
  instance_class      = "db.r4.large"
  publicly_accessible = false
  db_subnet_group_name = aws_db_subnet_group.default.name
}

resource "aws_db_instance" "rds_proxy" {
  identifier           = "aurora-proxy"
  db_instance_class    = "db.t3.small"
  engine               = "mysql"
  engine_version       = "8.0.20"
  allocated_storage    = 20
  db_subnet_group_name = aws_db_subnet_group.default.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  publicly_accessible  = false

  # Proxy configuration
  ca_cert_identifier = "rds-ca-2019"
  db_cluster_identifier = aws_rds_cluster.aurora.id
}

