# provider.tf
provider "aws" {
  region = "us-east-1"
}

# Create an SSH key pair
resource "aws_key_pair" "lightsail_key" {
  key_name   = "lightsail-key"
  public_key = file("~/.ssh/id_rsa.pub")
}

# Create Lightsail instance
resource "aws_lightsail_instance" "example" {
  name               = "my-lightsail-instance"
  availability_zone  = "us-east-1a"
  blueprint_id       = " amazon_linux " # You can choose other blueprints like ubuntu_18_04, etc.
  bundle_id          = "micro_2_0"      # You can choose other bundle types like "micro_2_0", "small_1_0", etc.

  # Attach the SSH key
  tags = {
    Name = "MyLightsailInstance"
  }

  # SSH key locations
  user_data = <<-EOF
    #!/bin/bash
    echo '${chomp(tls_private_key.lightsail_key.private_key_pem)}' > /home/ec2-user/.ssh/id_rsa
    chmod 600 /home/ec2-user/.ssh/id_rsa
    touch /home/ec2-user/.ssh/authorized_keys
    echo '${chomp(data.template_file.ssh_key_content.rendered)}' > /home/ec2-user/.ssh/authorized_keys
  EOF
}

# Creates a private key in the Terraform state 
resource "tls_private_key" "lightsail_key" {
  algorithm = "RSA"
  rsa_bits  = 4096
}

# Create a template for the SSH key content
data "template_file" "ssh_key_content" {
  template = "${file("~/.ssh/id_rsa.pub")}"
}

# Output the public IP of the instance
output "instance_public_ip" {
  value = aws_lightsail_instance.example.networking.ports[0].public_ipv4_address
}

