provider "aws" {
  region = "us-east-1" # Set this to your preferred AWS region
}

resource "aws_acm_certificate" "lightsail_cert" {
  domain_name       = "yourdomain.com" # Replace this with your Lightsail DNS domain
  validation_method = "DNS"

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.lightsail_cert.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }

  zone_id = "YOUR_ROUTE53_HOSTED_ZONE_ID" # Replace with your Route 53 hosted zone ID
  name    = each.value.name
  type    = each.value.type
  records = [each.value.record]
  ttl     = 60
}

resource "aws_acm_certificate_validation" "cert_validation" {
  certificate_arn         = aws_acm_certificate.lightsail_cert.arn
  validation_record_fqdns = [for record in aws_route53_record.cert_validation : record.fqdn]
}

resource "aws_lightsail_domain" "example" {
  domain_name = "yourdomain.com" # Replace with your Lightsail DNS domain
}

resource "aws_lightsail_domain_entry" "example" {
  domain_name = aws_lightsail_domain.example.domain_name
  domain_entry = "www.yourdomain.com" # Replace with your subdomain, e.g., www.yourdomain.com
  target_resource_name = "your_instance_name" # Replace with your Lightsail instance name
}

resource "aws_lightsail_certificate" "example" {
  certificate_name = "myCertificate"
  attachment_name  = "example-cert"

  domain_name = aws_lightsail_domain.example.domain_name
  private_key = tls_private_key.example.private_key_pem
  certificate_body = tls_self_signed_cert.example.cert_pem
}

resource "tls_private_key" "example" {
  algorithm = "RSA"
  rsa_bits  = 2048
}

resource "tls_self_signed_cert" "example" {
  key_algorithm   = tls_private_key.example.algorithm
  private_key_pem = tls_private_key.example.private_key_pem

  subject {
    common_name  = "yourdomain.com"
  }

  allowed_uses = [
    "server_auth",
  ]

  validity_period_hours = 8760

  dns_names = [
    "yourdomain.com"
  ]

  depends_on = [aws_acm_certificate_validation.cert_validation]
}

