provider "aws" {
  region = "us-east-1" # specify your desired AWS region
}

resource "aws_lightsail_instance" "origin" {
  name              = "lightsail-origin-instance" # specify your instance name
  availability_zone = "us-east-1a" # match this to your desired availability zone
  blueprint_id      = "amazon_linux_2"          # specify your instance blueprint
  bundle_id         = "nano_2_0"                # specify your bundle id
  key_pair_name     = "your-key-pair-name"      # your Lightsail key pair name
}

resource "aws_lightsail_distribution" "example" {
  name = "lightsail-distribution"

  origin_configuration {
    domain_name = aws_lightsail_instance.origin.public_domain_name
    pool_id     = aws_lightsail_instance.origin.id
    origin_path = "/"
  }

  cache_settings {
    behavior = "CACHING_OPTIMIZED"
    ttl      = 60
  }

  enabled_cache_behavior {
    is_enabled     = true
    behavior_type  = "SERVE_STRICTLY_CACHED_CONTENT"
    cache_response_on_error = false
    response_headers_policy {
      override {
        header_name = "strict-transport-security"
        header_value = "max-age=31536000; includeSubdomains"
      }
    }
    forwarding_rule {
      host_header              = "example.com"
      path_pattern             = "/images/*"
      protocol_policy          = "MATCH_REQUEST"
      redirect_http_to_https   = true
      viewer_protocol_policy   = "https-only"
    }
  }

  waf_enabled             = false

  delivery_addresses      = [aws_lightsail_instance.origin.public_ip]
  health_check {
    path = "/health"
  }

  attachment {
    instance_port = 80
    protocol      = "http"
  }
}

