        interval = 24
        interval_unit = "HOURS"
        times       = ["03:00"]
      }

      retain_rule {
        count    = 1
        unit     = "YEARS"
      }

      tag {
        key        = "Environment"
        value      = "Production"
        type       = "STRING"
      }

      transition {
        days          = 7
        storage        = "GLACIER"
      }
    }
  }
}

