  bucket = aws_s3_bucket.glacier_vault.bucket
  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "RestrictBucketAccessToGlacier",
      "Effect": "Allow",
      "Principal": {
        "AWS": "arn:aws:iam::123456789012:user/your_user"
      },
      "Action": "s3:PutObject",
      "Resource": "arn:aws:s3:::${var.bucket_name}/*",
      "Condition": {
        "StringEquals": {
          "s3:x-amz-acl": "bucket-grants"
        }
      }
  },
  {
    "Sid": "AddBucketAccessForGlacierOnly",
    "Effect": "Deny",
    "Principal": "*",
    "Action": "s3:*",
    "Resource": "arn:aws:s3:::glacier20240101-${var.bucket_name}",
    "Condition": {
      "StringEquals": {
        "aws:accesskey": "your_user_access_key"
      }
    }
  }
]
EOF

