variable "bucket_name" {
  type = string
}

resource "aws_s3_bucket" "glacier_vault" {
  bucket = var.bucket_name
  lifecycle {
    ignore_changes = [
      "acl",
      "policy",
    ]
  }
  tags = {
    Name = "Glacier Vault"
  }
}

resource "aws_s3_bucket_acl" "glacier_acl" {
  bucket = aws_s3_bucket.glacier_vault.id
  acl    = "private"
}

resource "aws_s3_bucket" "glacier_access_policy" {
  bucket = aws_s3_bucket.glacier_vault.bucket
  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "RestrictBucketAccessToGlacier",
      "Effect": "Allow",
      "Principal": {
        "AWS": "arn:aws:iam::123456789012:user/your_user"
      },
      "Action": "s3:PutObject",
      "Resource": "arn:aws:s3:::${var.bucket_name}/*",
      "Condition": {
        "StringEquals": {
          "s3:x-amz-acl": "bucket-grants"
        }
      }
  },
  {
    "Sid": "AddBucketAccessForGlacierOnly",
    "Effect": "Deny",
    "Principal": "*",
    "Action": "s3:*",
    "Resource": "arn:aws:s3:::glacier20240101-${var.bucket_name}",
    "Condition": {
      "StringEquals": {
        "aws:accesskey": "your_user_access_key"
      }
    }
  }
]
EOF

resource "aws_glacier_vault" "my_vault" {
  vault_name      = var.bucket_name
  policy          = aws_s3_bucket.glacier_access_policy.policy
}

output "glacier_vault_name" {
  value = aws_glacier_vault.my_vault.vault_name
}
```

Note: Replace `"your_user"` with the actual user and `"your_user_access_key"` with the actual access key where needed. The lifecycle rule might need additional permissions to ignore changes to the S3 Glacier Vault configuration.

