Certainly! Here is the Terraform configuration for creating an AWS Application Load Balancer in HCL format:

```hcl
provider "aws" {
  region = "us-east-1" # Change this to your desired AWS region
}

resource "aws_security_group" "alb" {
  name        = "my-app-load-balancer"
  description = "ALB security group"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol   = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port     = 0
    to_port       = 0
    protocol     = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb" "my_alb" {
  name               = "my-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb.id]
  subnets            = ["subnet-12345678", "subnet-87654321"] # Replace with your actual subnet IDs

  enable_deletion_protection = false

  access_logs {
    bucket  = aws_s3_bucket.load_logs.bucket
    bucket_prefix  = "alb"
  }
}

resource "aws_lb_target_group" "default" {
  name     = "my-alb-target-group"
  port     = 80 # Adjust according to your use case
  protocol = "HTTP"
  vpc_id   = "vpc-12345678" # Replace with your actual VPC ID
}

resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.my_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.default.arn
  }
}

resource "aws_s3_bucket" "load_logs" {
  bucket = "my-alb-logs"
  acl    = "log-delivery-write"
}
```

Replace placeholders like `subnet-12345678` and `vpc-12345678` with your specific subnet and VPC IDs. Adjust the `region`, `bucket`, and other IDs as necessary to fit your environment.

