  name = "nlb-network"
}

resource "google_compute_global_address" "nlb_global_address" {
  name = "nlb-global-address"
  ip_version = "IPV4"
  address_type = "EXTERNAL"
}

resource "google_compute_backend_service" "nlb_backend_service" {
  name            = "nlb-backend-service"
  protocol       = "HTTP"
  port_name       = "https"
  timeout_seconds = 30
}

resource "google_compute_forwarding_rule" "nlb_forwarding_rule" {
  name      = "nlb-forwarding-rule"
  target    = google_compute_backend_service.nlb_backend_service.self_link
  ip_protocol = "TCP"
  ip_port         = "80"
  load_balancing_scheme = "EXTERNAL"
  backend_service = google_compute_backend_service.nlb_backend_service.self_link
  region         = "your-region"
}

resource "google_compute_managed_ssl_certificate" "nlb_managed_ssl_certificate" {
  name = "nlb-ssl-certificate"
  managed {
    domains = [
      "your-domain.com"
    ]
  }
}

resource "google_compute_url_map" "nlb_url_map" {
  name = "nlb-url-map"
}

resource "google_compute_target_https_proxy" "nlb_target_https_proxy" {
  name      = "nlb-target-https-proxy"
  description = "NLB target HTTPS proxy"
  proxy_bind {
    https {
      ssl_certificates = [google_compute_managed_ssl_certificate.nlb_managed_ssl_certificate.self_link]
    }
  }
  url_map              = google_compute_url_map.nlb_url_map.self_link
  service              = google_compute_backend_service.nlb_backend_service.self_link
}

resource "google_compute_health_check" "nlb_health_check" {
  name                  = "nlb-health-check"
  protocol              = "TCP"
