    port   = "80"
    request_interval   = "5s"
    request_timeout    = "5s"
    healthy_threshold  = 2
    unhealthy_threshold = 2
  }
}

resource "google_compute_region_health_check" "nlb_region_health_check" {
  region = "your-region"
  health_check     = google_compute_health_check.nlb_health_check.self_link
}

resource "google_compute_health_check" "nlb_health_check" {
