provider "google" {
  project = "my-gcp-project"
  region  = "us-central1"
}

resource "google_compute_subnetwork" "internal_subnet" {
  name          = "internal-subnet"
  ip_cidr_range = "10.0.1.0/24"
  primary       = true
  region        = "us-central1"
  network      = google_compute_network.internal_network.name
}

resource "google_compute_network" "internal_network" {
  name   = "internal-network"
}

resource "google_compute_region_instance_group" "internal_instance_group" {
  name     = "internal-instance-group"
  zones    = ["us-central1-a", "us-central1-b", "us-central1-c"]
  network = google_compute_network.internal_network.name
  instances = [
    google_compute_instance.internal_instance_1.self_link,
    google_compute_instance.internal_instance_2.self_link,
  ]
}

resource "google_compute_instance" "internal_instance_1" {
  name         = "internal-instance-1"
  machine_type = "n1-standard-1"
  zone         = "us-central1-a"
  display_name = "Internal Instance 1"
}

resource "google_compute_instance" "internal_instance_2" {
  name         = "internal-instance-2"
  machine_type = "n1-standard-1"
  zone         = "us-central1-b"
  display_name = "Internal Instance 2"
}

resource "google_compute_region_instance_group_manager" "internal_manager" {
  base_instance_name      = google_compute_region_instance_group.internal_instance_GROUP.name
  instance_group         = google_compute_region_instance_group.internal_instance_GROUP.self_link
  region = google_compute_subnetwork.internal_subnetwork.region
}

resource "google_compute_load_balancer" "internal_lb" {
  name = "internal-load-balancer"
  subnetwork = google_compute_subnetwork.internal_subnet.id

  backend_service = google_compute_region_instance_group_manager.internal_manager.self_link

  health_checks {
    apply { # Apply a health check to your instances
      timeout = "2.0s"
      check_interval = "5.0s"
      unhealthy_threshold = 2
    }
  }
}
