  name                = "internal-vnet"
  address_space       = "10.0.0.0/16"
  location           = azurerm_network_interface.internal_interface.location
  resource_group_name = azurerm_network_interface.internal_interface.resource_group_name
}

resource "azurerm_public_ip" "lb_internal_ip" {
  name                       = "internal-lb"
  location                   = azurerm_network_interface.internal_interface.location
  resource_group_name          = azurerm_network_interface.internal_interface.resource_group_name
  allocation_method          = "Static"
  public_ip_address_allocation = "Dynamic"
}

resource "azurerm_lb" "internal_lb" {
  name                = "internal-lb"
  location            = azurerm_network_interface.internal_interface.location
  resource_group_name = azurerm_network_interface.internal_interface.resource_group_name

  frontend_ip_configuration {
    name            = "internal-inbound-configuration"
    public_ip_address = azurerm_public_ip.lb_internal_ip.id
  }
}

resource "azurerm_lb_backend_address_pool" "internal_backend_pool" {
  name                 = "internal-backend-pool"
  load_balancer        = azurerm_lb.internal_lb.id
  frontend_ip_configuration  = azurerm_lb_backend_address_pool.internal_lb_backend_address_pool.frontend_ip_configuration

  ip_configurations {
    ip_configuration {
      ip_address = "add your private IP address here"
    }
  }

  health_probe {
    load_balancer            = azurerm_lb_backend_address_pool.internal_lb
    protocol = "Http"
    request_path = "/health"
    response_match = "200"
  }
}
