```hcl
provider "google" {
  project = "your-project-id"
  region  = "your-region"
}

resource "google_compute_health_check" "nlb_health_check" {
  name        = "nlb-health-check"
  project     = var.project
  type        = "TCP" # or "HTTPS", "HTTP", etc.
  timeout     = 5
  tcp_health_check {
    port         = "80" # Specify the port you want to use
  }
}

resource "google_compute_target_pool" "nlb_target_pool" {
  project        = var.project
  region         = var.region
  name          = "nlb-target-pool"
  target_pools {
    targets {
      address            = "lb-ip-address"
      pool                = "nlb-target-pool" # Name of the target pool
    }
    health_checks = ["nlb-health-check"]
    health_checks = ["nlb-health-check"]
  }
}

resource "google_compute_forwarding_rule" "nlb_forwarding_rule" {
  name                  = "nlb-forwarding-rule"
  project               = var.project
  region                = var.region
  load_balancing_scheme = "EXTERNAL"
  backend_service       = google_compute_region_target_http_proxy.object.self_link
  health_check          = google_compute_health_check.nlb_health_check.self_link

# The forward rule will exist at the regional level with external forwarding rule only supported by NLB.
  backend_service {
    service   = google_compute_target_pool.nlb_target_pool.self_link
  }
}
```

Make sure to replace `"your-project-id"` and `"your-region"` with your actual Google Cloud project ID and region, and `"lb-ip-address"` with the actual IP address of the target NLB instance. Adjust the health check type and port according to your use case.

