provider "aws" {
  region = "us-west-2"
}

resource "aws_lb" "cognito_lb" {
  name               = "cognito-load-balancer"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.cognito_lb_sg.id]
}

resource "aws_security_group" "cognito_lb_sg" {
  name        = "cognito-lb-sg"
  description = "Security group for Cognito Load Balancer"

  ingress {
    protocol    = "tcp"
    from_port   = 443
    to_port     = 443
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    protocol    = "-1"
    from_port   = 0
    to_port     = 0
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb_listener" "cognito_auth_listener" {
  load_balancer_arn = aws_lb.cognito_lb.arn
  port             = 443
  protocol        = "HTTPS"

  default_action {
    type             = "authenticate-cognito"
    target_group_arn = aws_lb_target_group.cognito_target_group.arn
    ssl_policy       = "ELBSecurityPolicy-TLS-1-2-2017-01"
  }
}

resource "aws_lb_target_group" "cognito_target_group" {
  name     = "cognito-target-group"
  port     = 443
  protocol = "HTTPS"

  vpc_id = aws_vpc.main.id

  health_check {
    protocol = "HTTPS"
    path     = "/amazon-cognito-authorization"
    port     = "443"
  }
}

