  engine_version      = "8.0"
  instance_class      = "db.t3.micro"
  name                = "mydb"
  username            = "user"
  password            = "yourpassword"

  # Assume the S3 bucket and snapshot are in the same region
  storage_encrypted   = true
  kms_key_id          = aws_kms_key.mykey.arn

  enable_cloudwatch_logs_exports = ["error", "general", "slowquery"]

  skip_final_snapshot = true

  snapshot_identifier = "aws_db_snapshot_from_s3_generator"
}

resource "aws_s3_bucket" "my_bucket" {
  bucket = "my-restore-bucket"
}

resource "aws_s3_bucket_object" "s3_restore" {
  bucket = aws_s3_bucket.my_bucket.id
  key    = "mydb-snapshot-file.sql"
  source = "path/to/local/snapshot-file.sql"
}

resource "aws_iam_role" "s3_restore_role" {
  name = "s3_restore_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_policy" "s3_restore_policy" {
  name        = "s3_restore_policy"
  description = "Policy to allow RDS access to an S3 bucket"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.my_bucket.arn,
          "${aws_s3_bucket.my_bucket.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "s3_restore_policy_attachment" {
  role       = aws_iam_role.s3_restore_role.name
  policy_arn = aws_iam_policy.s3_restore_policy.arn
}

resource "aws_kms_key" "mykey" {
  description = "Key for encrypting database"
  policy      = <<POLICY
{
  "Version": "2012-10-17",
  "Id": "key-consolepolicy-3",
  "Statement": [
    {
      "Sid": "ControlAccess",
      "Effect": "Allow",
      "Principal": {
        "AWS": "arn:aws:iam::YOUR_ACCOUNT_ID:root"
      },
      "Action": "kms:*",
      "Resource": "*"
    }
  ]
}
POLICY
}
