}

resource "aws_efs_file_system" "example" {
  creation_token = "example" # A unique identifier for the file system
  performance_mode = "generalPurpose" # Can be "generalPurpose" or "maxIO"

  tags = {
    Name = "example-efs"
  }
}

resource "aws_efs_mount_target" "example" {
  count             = 1 # Specify the number of mount targets
  file_system_id    = aws_efs_file_system.example.id
  subnet_id         = "<your-subnet-id>" # Replace with your subnet ID
  security_groups   = ["<your-security-group-id>"] # Replace with your security group ID
}

resource "aws_efs_access_point" "example" {
  file_system_id = aws_efs_file_system.example.id

  posix_user {
    gid = 1001
    uid = 1001
    secondary_gids = [1002]
  }

  root_directory {
    path = "/example"
    creation_info {
      owner_gid   = 1001
      owner_uid   = 1001
      permissions = "755"
    }
  }
}

