resource "aws_efs_file_system" "efs_example" {
  creation_token = "efs-creation-token"
  performance_mode = "generalPurpose"

  lifecycle {
    ignore_changes = [creation_token]
  }
}

resource "aws_efs_mount_target" "efs_mount_target" {
  file_system_id  = aws_efs_file_system.efs_example.id
  subnet_id        = "subnet-0123456789abcdef0"
  ip_address      = "192.168.1.101" // Specify an IP within the subnet's range
  network_interface_id = "eni-0123456789abcdef0"
}

resource "aws_iam_role" "efs_role_example" {
  name = "EFSRole"

  assume_role_policy {
    version = "2012-10-17"
    statement = jsonencode({
      sid    = "",
      effect = "Allow",
      principals = [
        {
          type        = "Service",
          identifiers = ["elasticfilesystem.amazonaws.com"],
        }
      ],
      actions = ["sts:AssumeRole"],
    })
  }

  tags = {
    Name = "EFS Access Role"
  }
}

resource "aws_iam_policy" "efs_policy_example" {
  name   = "EFSAccessPolicy"
  description = "Policy to allow access to EFS"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "elasticfilesystem:ClientMount",
          "elasticfilesystem:ClientWrite",
          "elasticfilesystem:ClientWriteAndMount"
        ]
        Resource = ["*"]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVolumes",
          "ec2:DescribeMountTargets",
        ]
        Resource = ["*"]
      }
    ]
  })

  tags = {
    Name = "EFS Access Policy"
  }
}

resource "aws_iam_policy_attachment" "efs_policy_attachment" {
  name       = "EFSProducerPolicyAttachment"
  roles      = [aws_iam_role.efs_role_example.name]
  policy_arn = aws_iam_policy.efs_policy_example.arn
}
```

**Note**: Make sure to replace `subnet-0123456789abcdef0`, `192.168.1.101`, and `eni-0123456789abcdef0` with valid values from your AWS environment.

